        \draw[scalar]  (b13) -- (b3);
        \draw[vector,very thick,magenta] 
        (b2) -- node[label={above left, xshift=1mm, yshift=-1mm}:{\scriptsize $\xi$}] {} (b13);
        \draw[scalar]  (b2) -- (b5);
        \draw[scalar]  (b13) -- (b4);
