    \end{column}\pause
    \begin{column}{0.53\textwidth}
      \vspace{1mm}
      {\small
        COMPASS $3\pi$ PWA:
        \begin{itemize}
        \item $\pi^-\pi^+\pi^-$ final state,\\
          $m_{3\pi}<2.5\,$GeV, $0.1<t'<1\,$GeV$^2$,\pause
