\section*{Formalism}
\subsection*{Partial-wave decomposition}
\begin{frame}[noframenumbering]{Constraints on the full amplitude}{}
$$
A = \bra{3\pi}\hat{T}\ket{\pi \mathbb{P}} = \sum_{JMLS} F_{LS}^{JM}\, \text{PW}_{LS}^{JM}(\tau)
$$
Unitarity condition for the full amplitude $\Delta A = i \int A\, \diff\Phi\, T^\dagger$
\vspace{-0.4cm}
\begin{figure}[h!]
  \includegraphics[width=.6\textwidth]{figures/3pi_unitarity_isobar.pdf}
\end{figure}
\vspace{-0.3cm}
{\scriptsize $$
\Delta_{w^2}\,F_{LS}^{JM}(s_1,w^2)=2i\sum_{L'S'}\int_{(2m_{\pi})^2}^{(w-m_{\pi})^2}\,ds_1' \,\rho_3(s_1',w^2)\,T^{JM*}_{LSL'S'}(s_1,w^2,s_1')F^{JM}_{L'S'}(s_1',w^2)
$$}
\begin{itemize}
\item We use elastic approximation for $3\pi$, i.e. we neglect inelasticity.
\item Interaction can be considered for pairs (subsystems, isobars), i.e. three-body forces are negligible.
\end{itemize}
\vspace{0.3cm}
\end{frame}

\begin{frame}[noframenumbering]{Scattering amplitude}{$3\pi\to 3\pi$ matrix form}
{\scriptsize $$
T = \bra{3\pi}\hat{T}\ket{3\pi} = \sum_{JMLSL'S'} T_{LSL'S'}^{JM}\, \text{PW}_{LS}^{JM}(\tau)\, \text{PW}_{L'S'}^{JM}(\tau')
$$}
Unitarity condition for rescattering amplitude $\Delta T = i\int T\, \diff\Phi\, T^\dagger$
\vspace{-0.2cm}
\begin{figure}[h!]%[!tbp]
  \includegraphics[width=.6\textwidth]{figures/3pi_unitarity_isobar_2.pdf}
\end{figure}
\vspace{-0.5cm}
\scalebox{0.97}{\parbox{\textwidth}{
{\scriptsize 
$$
\Delta_{w^2}\,T_{LSL'S'}^{JM}(s_1,w^2,s_1')=2i\sum_{L''S''}\int_{(2m_{\pi})^2}^{(w-m_{\pi})^2} \mathrm{d}s_1'' \rho_3(s_1'',w^2)\,T^{JM*}_{LSL''S''}(s_1,w^2,s_1'')T^{JM}_{L''S''L'S'}(s_1'',w^2,s_1')
$$
}}}
\begin{itemize}
%\item Elastic approximation of $3\pi$.
%\item Interaction can be consider for pairs (subsystems, isobars), i.e. 3 body forces are negligible.
\item The $(\pi\pi)$-subsystems freely scatter to each other.
$$
T = \bra{\xi\pi}\hat{T}\ket{\xi'\pi}, \quad\text{e.g. }
T=
\begin{pmatrix}
T_{\rho\pi\to\rho\pi} & T_{\rho\pi\to f_2\pi} \\
T_{f_2\pi\to\rho\pi} & T_{f_2\pi\to f_2\pi} \\
\end{pmatrix}.
$$
\item Unitarity equations are written in matrix form.
\end{itemize}
\end{frame}

\subsection*{Parametrization}

\begin{frame}[noframenumbering]{K-matrix approach}
  $$
  T = \frac{K}{1-i\tilde{\rho}K} = 
  K + K \left[i\tilde{\rho}\right] K + K \left[i\tilde{\rho}\right] K \left[i\tilde{\rho}
  \right] K \left[i\tilde{\rho}\right] K+ \dots
  $$
where $i\tilde{\rho}$ is a diagonal matrix of loop integrals (Chew-Mandelstam).
\begin{itemize}
\item K-matrix parametrization of $T$ satisfies unitarity by construction.
\item The approach takes into account rescattering through $K$-potential (resonances).
