  \begin{itemize}
  \item {\bf Production process via an exchange does not satisfy probability conservation.}
  \item Rescattering (Unitarisation) term has to be added.
% The unitarisation term is required by unitarity constraint as soon as long-range production is present
  \item In the limit of short range the production amplitude is approximated by a constant $c_{LS}$.
  \item Amplitude has correct threshold behavior due to factors $C_{LS}$.
  \end{itemize}
{\scriptsize
\begin{multline*}
F_{LS}(w^2) = b_{LS}(w^2) + C_{LS}(w^2) \hat{T}_{LSL'S'}(w^2) c_{L'S'} \,+ \\ 
+ C_{LS}(w^2)\frac{\hat{T}_{LSL'S'}(w^2)}{2\pi}\int \frac{\rho_{L'S'}(s') b_{L'S'}(s') C_{L'S'}(s')}{s'-w^2}\mathrm{d}s'
\end{multline*}
}
