  \item Extra rotation (wigner) to match helicities due to the spin of $\psi'$
  \end{itemize}
\item Tensor formalism \paper{Fillipini et. al; BG (1998)}:
  \begin{itemize}
  \item explicitely Lorentz-invariant $A = \varepsilon_\mu(p_\psi,\lambda_\psi) A^{\mu}$
  \item but introduces some dynamical assumptions ($\gamma$-factors \paper{Chung})
  \end{itemize}
\item [$\Rightarrow$] {\color{red} Mixed approach} {\paper{Jackson-Hite (1968); Collins (1977)}}
  \begin{itemize}
  \item[$\to$] write any tensor amplitude
  \item[$\to$] match to helicity PWs
  \item[$\to$] introduce contrains of the dependence on threshold $A_L \xrightarrow[s\to s_{\text{th}}]{} (\sqrt{s}-\sqrt{s}_{\text{th}})^{L}$
  \end{itemize}
\end{itemize}
{\small
We get analytic, cross-symmetric, explicitely Lorentz-invariant amplitude
}
\end{frame}

