\begin{frame}{Dispersive approach}{First interaction in Khuri-Treiman series}
  \vspace{-.8cm}
  $$
  \begin{tikzpicture}[node distance=0.6cm and 0.9cm, baseline=0cm]
    \coordinate[] (a1);
    \coordinate[right=of a1] (a2); 
    \coordinate[above right=of a2] (b1); 
    \coordinate[      right=of a2] (b2); 
    \coordinate[below right=of a2] (b3); 
    \draw[vector] (a1) -- (a2);
    \draw[scalar] (a2) -- (b1);
    \draw[scalar] (a2) -- (b2);
    \draw[scalar] (a2) -- (b3);
    \draw[decorate,decoration={brace,amplitude=2pt}]
    ([xshift=+.1cm,yshift=+.1cm]b1) -- ([xshift=+.1cm,yshift=-.1cm]b2) 
    node [black,midway,xshift=0.3cm] {\footnotesize $\sigma_s$};
    \draw[decorate,decoration={brace,amplitude=2pt}]
    ([xshift=+.3cm,yshift=+.1cm]b2) -- ([xshift=+.3cm,yshift=-.1cm]b3)
    node [black,midway,xshift=0.3cm] {\footnotesize $\sigma_t$};
    \fill[black] (a2) circle [radius=0.2];
  \end{tikzpicture} = 
  A^{(s)}+A^{(t)}+A^{(u)},\quad 
  {\tiny
  A^{(j)} = \sum_l (2l+1) {\color{red}a_l}^{(j)}(s_{j}) P_l(\cos\theta^{(j)}) 
  }$$
  \vspace{-0.3cm}
  $$ \text{Due to unitarity: } \
  {\color{red} a_l}^{(s)} = \underbrace{{\color{tlColor}t_l}^{(s)} c_l^{(s)}}_{\text{Isobar model}} + 
  \underbrace{\frac{{\color{tlColor}t_l}^{(s)}}{2\pi}\int\frac{b_l^{(s)}\rho}{\sigma_s'-\sigma_s}\diff
    \sigma_s'}_{\text{rescattering corrections}}.
  $$
  \vspace{-0.3cm}
  \begin{columns}
    \begin{column}{0.7\textwidth}
      \begin{itemize}
      \item $a_l^{(s)}$ is the corrected two-body amplitude,
      \item $b_l^{(s)}$ is the projection of cross channel waves.
      \item Integral eqs. can be solved by perturbations.
      \end{itemize}
      \vspace{0.3cm}
      $$  
      \begin{tikzpicture}[node distance=0.4cm and 0.6cm, baseline=0cm]
        \coordinate[] (a1);
        \coordinate[right=of a1] (a2); 
        \coordinate[below right=of a2] (a3); 
        \coordinate[above right=of a2] (b3); 
        \coordinate[below right=of b3] (c1); 
        \coordinate[      right=of b3] (c2); 
        \draw[vector] (a1) -- (a2);
        \draw[scalar] (a2) -- (a3);
        \draw[red, line width=.1cm] (a2) -- (b3);
        \draw[scalar] (b3) -- (c1);
        \draw[scalar] (b3) -- (c2);
        \fill[black] (a2) circle [radius=0.2];
        \fill[black] (b3) circle [radius=0.1];
      \end{tikzpicture}
      =
      \begin{tikzpicture}[node distance=0.4cm and 0.6cm, baseline=0cm]
        \coordinate[] (a1);
        \coordinate[right=of a1] (a2); 
        \coordinate[below right=of a2] (a3); 
        \coordinate[above right=of a2] (b3); 
        \coordinate[below right=of b3] (c1); 
        \coordinate[      right=of b3] (c2); 
        \draw[vector] (a1) -- (a2);
        \draw[scalar] (a2) -- (a3);
        \draw[vector,tlColor] (a2) -- (b3);
        \draw[scalar] (b3) -- (c1);
        \draw[scalar] (b3) -- (c2);
        \fill[black] (a2) circle [radius=0.2];
        \fill[tlColor] (b3) circle [radius=0.1];
      \end{tikzpicture}
      +
      \begin{tikzpicture}[node distance=0.4cm and 0.6cm, baseline=0cm]
        \coordinate[] (a1);
        \coordinate[right=of a1] (a2); 
        \coordinate[below right=of a2] (a3); 
        \coordinate[      right=of a3] (a4); 
        \coordinate[above right=of a2] (b3); 
        \coordinate[      right=of b3] (c1); 
        \coordinate[      right=of c1] (d1); 
        \coordinate[below right=of c1] (d2); 
        \draw[vector] (a1) -- (a2);
        \draw[red, line width=.1cm] (a2) -- (a3);
        \draw[scalar] (a3) -- (a4);
        \draw[scalar] (a2) -- (b3);
        \draw[scalar] (a3) -- (b3);
        \draw[vector,tlColor] (b3) -- (c1);
        \draw[scalar] (c1) -- (d1);
        \draw[scalar] (c1) -- (d2);
        \fill[black] (a2) circle [radius=0.2];
        \fill[black] (a3) circle [radius=0.1];
        \fill[tlColor] (c1) circle [radius=0.1];
        \fill[tlColor] (b3) circle [radius=0.1];
      \end{tikzpicture}
      $$
    \end{column}
    \begin{column}{0.3\textwidth}
        \includegraphics[width=\textwidth]{figures/disc_sctr_math.pdf}
    \end{column}
  \end{columns}
\end{frame}

