\begin{frame}{Dalitz Plot Decomposition (DPD)}
  \begin{columns}
    \begin{column}{0.55\textwidth}
      % \centering
      \begin{columns}
        \begin{column}{0.5\textwidth}
          \includegraphics[width=\textwidth]{Penta_decay_indication.pdf}          
        \end{column}
        \begin{column}{0.45\textwidth}
          \small Spin in 3-body decays\\
          \paper{MM et al. PRD (2019)}
        \end{column}
      \end{columns}
%       % \scalebox{0.6}{\parbox{\textwidth}{$$
%       % I = \sum_\text{pol.} |A_{\lambda_0,\lambda_1,\lambda_2}|^2
%       % $$}}
      \vspace{-2mm}
      \scalebox{0.8}{\parbox{\textwidth}{$$ 
      A_{\lambda_0,\lambda_1,\lambda_2} = 
        \underbrace{\raisebox{-0.5\height}{\includegraphics[width=0.27\textwidth]{general_isobar_12.pdf}}}_{A^{(12)}_{\lambda_0,\lambda_1,\lambda_2}} + 
        \underbrace{\raisebox{-0.5\height}{\includegraphics[width=0.27\textwidth]{general_isobar_23.pdf}}}_{A^{(23)}_{\lambda_0,\lambda_1,\lambda_2}} +
        \underbrace{\raisebox{-0.5\height}{\includegraphics[width=0.27\textwidth]{general_isobar_31.pdf}}}_{A^{(31)}_{\lambda_0,\lambda_1,\lambda_2}}
      $$}}
    \end{column}
    \begin{column}{0.37\textwidth}
      \vspace{-6mm}
      \begin{overpic}[width=\textwidth]{Dalitz_plot_pc.pdf}
        % \put(60,30) {\includegraphics[width=0.25\textwidth]{Penta_isobar_12.pdf}}
        % \put(30,60) {\includegraphics[width=0.25\textwidth]{Penta_isobar_23.pdf}}
      \end{overpic}
    \end{column}
  \end{columns}
  \pause
  \vspace{-5mm}
  \begin{columns}
    \begin{column}{0.5\textwidth}
      \begin{exampleblock}{}
        \textbf{Used in the past}
        \centering
        \scalebox{0.6}{\parbox{\textwidth}{$$
        A_{\lambda_0,\lambda_1,\lambda_2}^{(23)} = 
          \underbrace{\blackhatchedsquare(\phi_i,\theta_i)}_{0\to X,1} \times
          \underbrace{\blackhatchedsquare(\phi_i',\theta_i')}_{X\to 2,3} \times
          \underbrace{\bluehatchedsquare(\phi_i'',\theta_i'')}_{\text{spin align.}}
        $$}}
        \small
        \vspace{-2mm}
        \begin{itemize}
          \item "impossible" to get right
          \item spin $1/2$: $A(\pi) \neq A(-\pi)$
          \item range of $\phi$ matters $[-\pi,\pi]$ vs $[0,2\pi]$
        \end{itemize}
        \end{exampleblock}      
    \end{column}
    \begin{column}{0.44\textwidth}
      \begin{exampleblock}{}
        \textbf{Proposed in DPD}
        \centering
        \scalebox{0.6}{\parbox{\textwidth}{$$
        A_{\lambda_0,\lambda_1,\lambda_2} = \sum_{\nu} D^{1/2*}_{\lambda_0,\nu}(\alpha,\beta,\gamma) \underbrace{O_{\lambda_1,\lambda_2}^{\nu}(m_{12}^2,m_{23}^2)}_{O^{(12)}+O^{(23)}+O^{(31)}}
        $$}}\\
        \vspace{-3mm}
        \scalebox{0.6}{\parbox{\textwidth}{$$
        O_{\nu,\lambda_1,\lambda_2}^{(23)}(m_{12}^2,m_{23}^2) = 
          \underbrace{\blackhatchedsquare}_{0\to X,1} \times
          \underbrace{\blackhatchedsquare}_{X\to 2,3} \times
          \underbrace{\bluehatchedsquare}_{\text{spin align.}}
        $$}}
        \vspace{-1mm}
        \small
        \begin{itemize}
          \item correct by construction
        \end{itemize}
      \end{exampleblock}
    \end{column}
  \end{columns}
  % \vspace{mm}
  \begin{columns}
    \begin{column}{0.7\textwidth}
      \vspace{-2mm}
      \begin{alertblock}{}
        \small
        Consequences of the incorrect spin matching:
        \begin{itemize}
          \item Unpolarized decay is not inhomogenious
          \item Observed intensity is $2\pi$ discontinuous in $\phi$
          \item Broad components are impacted the most
          \item Determination of $J^P$ might be incorrect
          % \item \raisebox{-0.5\height}{\includegraphics[width=0.32\textwidth]{Penta_isobar_12.pdf}}
        \end{itemize}    
      \end{alertblock}
    \end{column}
    \begin{column}{0.25\textwidth}
      \scalebox{0.6}{\parbox{1.2\textwidth}{
        Impacted analyses:
        \begin{align*}
          \fbox{$P_{cs}$} &&& \Xi_b^- \to J/\psi \Lambda^0 K^-\,\,\text{just published} \\
          \fbox{$Z, X$}   &&& B^- \to J/\psi \phi K^-\,\,\text{at RC} \\
          \fbox{CPV}      &&& \Xi_b^- \to K^- p K^-\,\,\text{at RC} \\
          \fbox{$P_{c}$}  &&& B_s^0 \to J/\psi p \bar{p}\,\,\text{at RC} \\
          \fbox{$Z$}      &&& B^0 \to J/\psi (\psi') \pi^+ K^- \\
          \fbox{$H_{\lambda,\lambda}$}  &&& \Lambda_c^+ \to p K^- \pi^+
        \end{align*}}}
    \end{column}
  \end{columns}
\end{frame}

