\subsection{Coupled-channel analysis}
\begin{frame}{Coupled-channel amplitude\hfill\paper{A.Rodas,A.Pilloni,MM,et al. (JPAC), PRL122 (2019)}}
  \begin{block}{Scattering amplitude: $\eta^{(\prime)}\pi\to\eta^{(\prime)}\pi$, $P/D$-waves}
  \begin{columns}
    \begin{column}{0.41\textwidth}
      $$ T = \frac{\color{blue} \Nfun(s)}{\color{red} \Dfun(s)} $$
      \begin{itemize}
        \item 2 \Kmat-matrix pole for $D$-wave
        \item 1 \Kmat-matrix pole for $P$-wave
      \end{itemize}
    \end{column}
    \begin{column}{0.58\textwidth}
      \begin{align*}
      \rho\Nfun^J_{ki}(s') &= \delta_{ki} \,\frac{(p_{\eta^{(\prime)}\pi}\sqrt{s}/2)^{2J+1}}{\left(s'+s_L\right)^{2J+1+\alpha}},\\ % \lambda^{J+1/2}\left(s',m_{\eta^{(\prime)}}^2,m_\pi^2\right)
      \Dfun^J_{ki}(s) &=  \left[ {\Kmat^J(s)}^{-1}\right]_{ki} - \frac{s}{\pi}\int_{s_{k}}^{\infty}ds'\frac{\rho \Nfun^J_{ki}(s') }{s'(s'-s - i\epsilon)}.
    \end{align*}
    \end{column}
  \end{columns}
  \end{block}
  \begin{block}{Production amplitude: $\pi\Po\to\eta^{(\prime)}\pi$, $P/D$-waves}
  \begin{columns}
    \begin{column}{0.45\textwidth}
      $$a = \frac{\color{blue} n(s)}{\color{red} \Dfun(s)} $$
      \begin{itemize}
        \item left poles to model unknown production function $n(s)$
      \end{itemize}
    \end{column}
    \begin{column}{0.54\textwidth}
      $$
      a^J_i(s) = q^{J-1} p_i^J \, \sum_k \nfun^J_k(s) \left[ {\Dfun^J(s)}^{-1} \right]_{ki}
      $$
    \end{column}
  \end{columns}
  \end{block}
  \begin{itemize}
    \item $D(s)$ has only the right-hand cut.
    \item $N(s)$ and $n(s)$ have the left-hand cut only (exchanges)
  \end{itemize}
\end{frame}

