\subsection{Deck mechanism}

\begin{frame}{Model for the forward scattering\hfill\paper{MM, A.Jackura (JPAC) in preparation}}{Deck effect}
  \begin{equation}
    \raisebox{-0.5\height}{\includegraphics[scale=0.7]{in-line-figures/deck_calculation.pdf}} = (T_{\pi_1 p})_{\lambda\lambda'}\,\frac{1}{m_{\pi}^2-t_1} \, T_{\pi_2\pi_3}
  \end{equation}
\begin{itemize}
  \item Two diagrams ($\pi^{-}$ symmetrization)
  $$
  \mathcal{B}_{\lambda\lambda'} = \mathcal{B}_{\lambda\lambda'}^{(1)} + \mathcal{B}_{\lambda\lambda'}^{(3)}
  $$
  \item High energy $p\pi$ scattering
  \item $\pi\pi$ scattering dominated by resonances in lower partial waves
  \begin{itemize}
    \item Relative strength of $S$, $P$, $D$-waves is controlled by unitarity
  \end{itemize}
  {\scriptsize
  \begin{align*}
   {\mathcal B}^{(1)} = s_{\pi p} F(t)\,\frac{\mathrm{FF}(t_1)}{m_\pi^2-t_1} \bigg[&
     \frac{2}{3}\,t^{(\sigma_1,f_0)}(\sigma_1)
     + 3\,t^{(\rho)}(\sigma_1,t_1) P_1(\cos\theta_{\pi\pi}) + \frac{10}{3}\, t^{(f_2)}(\sigma_1,t_1) P_2(\cos\theta_{\pi\pi})
   \bigg].
 \end{align*}}
\end{itemize}
\end{frame}

\begin{frame}{Comparison with the COMPASS data\hfill\paper{MM PhD thesis}}
  \begin{columns}
    \begin{column}{0.64\textwidth}
      \includegraphics[width=\textwidth]{pict/deck/deck_ana_projections.pdf}
    \end{column}
    \begin{column}{0.35\textwidth}
      Pion propagator:
      \begin{itemize}
        \item Standard Deck
        $$
        \frac{1}{m_\pi^2 -t_1},
        $$
        \item Regge Deck
        $$
        \frac{e^{-i\pi \alpha(t_1)/2}}{m_\pi^2 -t_1}
        \left(\frac{s'-u'}{2s_\mathrm{sc}}\right)^{\alpha(t_1)},
        $$
        \item Form-factored Deck
        $$
        \frac{e^{b t_1}}{m_\pi^2 -t_1},
        $$
      \end{itemize}
    \end{column}
