\begin{frame}[noframenumbering]{The spurious pole in the Breit-Wigner model}
  {Energy dependent width, stable particles}
{\scriptsize
$$
t(s) = \frac{1}{m^2-s-im\Gamma(s)},\quad \Gamma(s) = \Gamma_0 \frac{p(s)}{p(m^2)}\frac{m}{\sqrt{s}},\quad
p(s) = \frac{\sqrt{(s-(m_1+m_2)^2)(s-(m_1-m_2)^2)}}{2\sqrt{s}}.
$$
Example: $m_1 = 140$\,MeV, $m_2 = 770$\,MeV, $m = 1.26\,$GeV, $\Gamma_0 = 0.5\,$GeV}
