\begin{frame}{$a_1(1420)$ interpretations}
  \begin{exampleblock}{Possible scenaria}
    \begin{itemize}
      \item \textbf{Pole} in the amplitude -- Genuine resonance
      \begin{itemize}
        \item<2-> Tetraquark state \paper{Z.-G. Wang (2014)}, \paper{H.-X.Chen et al. (2015)}, \paper{T. Gutsche et al. (2017)}
        \item<2-> $K^*\bar{K}$ molecule \paper{T. Gutsche et al. (2017)}
      \end{itemize}
      \item Singularity of the \textbf{non-pole} type
      \begin{itemize}
        \item<3-> Interference with background --- interplay between distant cuts
        \item<4-> \textbf{Rescattering} from $K^*\bar{K}$ ---  Triangle singularity
      \end{itemize}
    \end{itemize}
  \end{exampleblock}
