\section{Scattering theory}
\subsection{Two-body system}
\begin{frame}{Scattering experiment}
\begin{columns}
 \begin{column}{0.4\textwidth}
\includegraphics[width=0.96\textwidth]{pictborm/scatt.png}
 \end{column}
 \begin{column}{0.56\textwidth}
  \begin{itemize}
   \item We start with elastic scattering.
   \item We scan over energy of the system and find a preferable energy
   (peak of cross section)
   \item for a short time our particles prefer to form intermediate state
  \end{itemize}
 \end{column}
\end{columns}

\begin{equation*}
 t(s) = \langle f|T|i\rangle = \frac{g^2}{m^2-s-im\Gamma}, \quad \sigma(s) \sim \left|t(s)\right|^2 \rho(s).
\end{equation*}
$\rho$ is two-body phase space. $\tilde{\rho}$ is scalar two-body loop expression.
{\small
\begin{equation*}% = \frac{K}{1-ig^2\tilde{\rho}K/2}
  K + K \left[ig^2\tilde{\rho}/2\right] K + K \left[ig^2\tilde{\rho}/2\right] K \left[ig^2\tilde{\rho}/2\right] K+ \dots = 
  \frac{1}{K^{-1}-ig^2\tilde{\rho}/2}
\end{equation*}}
\vspace{-0.5cm}
\begin{figure}
\centering
\includegraphics[width=.8\textwidth]{pictborm/twobody_inv.pdf}
\end{figure}
\vspace{-0.1cm}
Notice if $K = g^2/(m^2-s)$, then we get Breit-Wigner formula.
\end{frame}

\begin{frame}{Two-body unitarity}
Conservation of probability gives the unitarity condition
\begin{equation*}
 SS^\dagger = 1,\quad S = 1+iT \enspace \Rightarrow \enspace T-T^\dagger = i\, T\, T^\dagger
\end{equation*}
\begin{equation*}
 t = \langle f|T|i\rangle, \quad \Delta t = i\, t^\star\, \rho\, t.
\end{equation*}
The general solution of the unitarity equation is 
$$
t(s) = \frac{1}{K^{-1}(s)-ig^2\tilde{\rho}(s)/2}, \text{ where } \tilde{\rho} = \frac{s}{i \pi}\int \frac{\rho(s')}{s'(s'-s)}\mathrm{d}s'.
$$
We find the reason the peak at second sheet, it is a pole of $t(s)$.
Any resonance is associated with a pole.\\
