\subsection*{KT equations}

\begin{frame}[noframenumbering]{KT: Basic idea}
\begin{itemize}
\item Amplitude for every sub-channel is the sum of ``isobars''.
 \begin{equation*}
  A(s,t,u) = A^{(s)}+A^{(t)}+A^{(u)}, \quad A^{(s)}(s,t,u) = \sum a_l^{(s)} P_l(z_s)
 \end{equation*}
 \item Two contributions to the projection on the partial sub-channel amplitude.
 \begin{equation*}
  f_l^{(s)} = \underbrace{a_l^{(s)}}_{\text{isobar}}+ \underbrace{b_l^{(s)}}_{\text{projections}} \quad A(s,t,u) = \sum f_l^{(s)} P_l(z_s)
 \end{equation*}
 \item The projections to the sub-channel from cross sub-channels.
 \begin{equation*}
   b_l^{(s)} = \int \diff z_s \,
   \left[ A^{(t)} + A^{(u)} \right] P_l(z_s)
 \end{equation*}
  \item Unitarity consistency equation.
 \begin{equation*}
   a_l^{(s)} = 
   \underbrace{t_l^{(s)}}_{\text{2b. interaction}} 
   \left( c^{(s)} + \frac{1}{\pi} \int\diff s'\, 
   \frac{b_l^{(s)}(s') \rho^{(s)}(s') }{s'-s} \right)
 \end{equation*}
\end{itemize} 
\end{frame}

\begin{frame}[noframenumbering]{KT: solution of equation}
We have integral equations for $b_l^{(i)}$, $i\in\{s,t,u\}$. All sub-channels are coupled.
\begin{equation*}
  \begin{pmatrix}
    b_l^{(s)}\\ \vdots\\b_l^{(t)}\\ \vdots\\b_l^{(u)}
  \end{pmatrix} = L \times
  \begin{pmatrix}
    c_l^{(s)}\\ \vdots\\c_l^{(t)}\\ \vdots\\c_l^{(u)}
  \end{pmatrix} + \underbrace{\hat{K}}_{\text{int.op.}}
    \begin{pmatrix}
    b_l^{(s)}\\ \vdots\\b_l^{(t)}\\ \vdots\\b_l^{(u)}
  \end{pmatrix}.
 \end{equation*}
If we solve it then our {\bf corrected isobar amplitude} is
\begin{equation*}
    a_l^{(j)} = \overbrace{t_l^{(j)} \big( c_l^{(j)}}^{\text{isobar}} + \overbrace{\underbrace{\hat{M}}_{\text{int.op.}} b_l^{(j)}}^{\text{correction to IM}}  \big)
\end{equation*}
\end{frame}

\begin{frame}[noframenumbering]{KT: Input and output}
Input 
\begin{itemize}
 \item fixed number of channel($s$,$t$,$u$) and partial waves $l=0,1,2$;
 \item elastic two body interaction $t_l^{(j)}$ parameterizated by
 \begin{itemize}
  \item a phase shift (Omn\'es approach),
  \item a pole position (Breit-Wigner approach);
 \end{itemize}
 \item couplings as parameters $c_l^{(j)}$
 \end{itemize}
Output: corrected isobar amplitudes $a_l^{(j)}$.
\begin{equation*}
 A(s,t,u) = A^{(s)}+A^{(t)}+A^{(u)}, \quad A^{(s)}(s,t,u) = \sum a_l^{(s)} P_l(z_s)
\end{equation*}
$ \Rightarrow $ for every set of parameters need to solve integral equations. (Every step of the fit)
{\color{red} Not good. Too slow.}
\end{frame}

