 $\Rightarrow $ physical background
\vspace{-0.3cm}
{\scriptsize
$$
 A(s) = \underbrace{\alpha(s)}_{1+\text{background}}\times \overbrace{T(s),}^{\text{resonance part}}
 \, s\text{ is squared $3\pi$-invariant mass.}
 $$
}
\vspace{-0.3cm}
\item Unitarity has to be respected $S\times S^\dagger = \mathbb{I}$.
$$
S = \mathbb{I} + i\, T.
% \tilde\rho (s)= \int_{(m_1+m_2)^2}^{(\sqrt{s}-m_3)^2} \frac{\mathrm{d}s_{12}}{2\pi} 
% \frac{2m\Gamma(s_{12})}{(m^2-s_{12})^2 + m^2\Gamma^2(s_{12})}\, \rho(s,s_{12},m_3^2)
$$
\item We work at a quasi-two-body approximation.
\end{itemize}
