\end{frame}

\begin{frame}{Representation}
  \vspace{-0.4cm}
  {\scriptsize
    $$A^{(s)}_{S} = (c_{s} a_{s}^{\text{direct}} + {\color{blue}c_{P}} a_{s}^{\text{induces}})P_0(\cos\theta_s),\qquad 
    A^{(s)}_P = (c_{P} a_{P}^{\text{direct}} + {\color{blue}c_{S}} a_{P}^{\text{induces}})P_1(\cos\theta_s)
    $$ 
  }
  \vspace{-0.4cm}
\begin{itemize}
\item $(\pi\pi)_P$ is a source $\Rightarrow$ $(\pi\pi)_P$ gets modified, $(\pi\pi)_S$ is induced.
    \begin{overpic}[width=0.36\textwidth]{pict/rhorho.pdf}
