\begin{frame}{Formalism}{Khuri-Treiman equation {\tiny\color{purple} [Phys.Rev. 119, 1115 (1960)]}}
  \vspace{-.8cm}
  $$ 
  \begin{tikzpicture}[node distance=0.6cm and 0.9cm, baseline=0cm]
    \coordinate[] (a1);
    \coordinate[right=of a1] (a2); 
    \coordinate[above right=of a2] (b1); 
    \coordinate[      right=of a2] (b2); 
    \coordinate[below right=of a2] (b3); 
    \draw[vector] (a1) -- (a2);
    \draw[scalar] (a2) -- (b1);
    \draw[scalar] (a2) -- (b2);
    \draw[scalar] (a2) -- (b3);
    \draw[decorate,decoration={brace,amplitude=2pt}]
    ([xshift=+.1cm,yshift=+.1cm]b1) -- ([xshift=+.1cm,yshift=-.1cm]b2) 
    node [black,midway,xshift=0.3cm] {\footnotesize $s$};
    \draw[decorate,decoration={brace,amplitude=2pt}]
    ([xshift=+.3cm,yshift=+.1cm]b2) -- ([xshift=+.3cm,yshift=-.1cm]b3)
    node [black,midway,xshift=0.3cm] {\footnotesize $t$};
    \fill[black] (a2) circle [radius=0.2];
  \end{tikzpicture} = 
  A^{(s)}+A^{(t)}+A^{(u)},\quad 
  {\tiny
  A^{(j)} = \sum_l (2l+1) {\color{red}a_l}^{(j)}(s_{j}) P_l(\cos\theta^{(j)}) 
  }$$
  \vspace{-0.3cm}
  $$ \text{Due to unitarity: } \
  {\color{red} a_l}^{(s)} = \underbrace{{\color{tlColor}t_l}^{(s)} c_l^{(s)}}_{\text{Isobar model}} + 
  \underbrace{\frac{{\color{tlColor}t_l}^{(s)}}{2\pi}\int\frac{b_l^{(s)}\rho}{s'-s}\diff
    s'}_{\text{rescattering corrections}}.
  $$
  \vspace{-0.3cm}
  \begin{itemize}
  \item $a_l^{(s)}$ is the corrected two-body amplitude,
  \item $b_l^{(s)}$ is the projection of cross channel waves.
  \item We get a system of integral equations.
  \end{itemize}
  \vspace{0.3cm}
  $$  
  \begin{tikzpicture}[node distance=0.4cm and 0.6cm, baseline=0cm]
    \coordinate[] (a1);
    \coordinate[right=of a1] (a2); 
    \coordinate[below right=of a2] (a3); 
    \coordinate[above right=of a2] (b3); 
    \coordinate[below right=of b3] (c1); 
    \coordinate[      right=of b3] (c2); 
    \draw[vector] (a1) -- (a2);
    \draw[scalar] (a2) -- (a3);
    \draw[red, line width=.1cm] (a2) -- (b3);
    \draw[scalar] (b3) -- (c1);
    \draw[scalar] (b3) -- (c2);
    \fill[black] (a2) circle [radius=0.2];
    \fill[black] (b3) circle [radius=0.1];
  \end{tikzpicture}
  =
  \begin{tikzpicture}[node distance=0.4cm and 0.6cm, baseline=0cm]
    \coordinate[] (a1);
    \coordinate[right=of a1] (a2); 
    \coordinate[below right=of a2] (a3); 
    \coordinate[above right=of a2] (b3); 
    \coordinate[below right=of b3] (c1); 
    \coordinate[      right=of b3] (c2); 
    \draw[vector] (a1) -- (a2);
    \draw[scalar] (a2) -- (a3);
    \draw[vector,tlColor] (a2) -- (b3);
    \draw[scalar] (b3) -- (c1);
    \draw[scalar] (b3) -- (c2);
    \fill[black] (a2) circle [radius=0.2];
    \fill[tlColor] (b3) circle [radius=0.1];
  \end{tikzpicture}
  +
  \begin{tikzpicture}[node distance=0.4cm and 0.6cm, baseline=0cm]
    \coordinate[] (a1);
    \coordinate[right=of a1] (a2); 
    \coordinate[below right=of a2] (a3); 
    \coordinate[      right=of a3] (a4); 
    \coordinate[above right=of a2] (b3); 
    \coordinate[      right=of b3] (c1); 
    \coordinate[      right=of c1] (d1); 
    \coordinate[below right=of c1] (d2); 
    \draw[vector] (a1) -- (a2);
    \draw[red, line width=.1cm] (a2) -- (a3);
    \draw[scalar] (a3) -- (a4);
    \draw[scalar] (a2) -- (b3);
    \draw[scalar] (a3) -- (b3);
    \draw[vector,tlColor] (b3) -- (c1);
    \draw[scalar] (c1) -- (d1);
    \draw[scalar] (c1) -- (d2);
    \fill[black] (a2) circle [radius=0.2];
    \fill[black] (a3) circle [radius=0.1];
    \fill[tlColor] (c1) circle [radius=0.1];
    \fill[tlColor] (b3) circle [radius=0.1];
  \end{tikzpicture}
  $$
\end{frame}

\begin{frame}{Input/Output}
  Model is given by
  \begin{itemize}
  \item Set of waves up to $l_j$ for every channel $j\in\{s,t,u\}$.\\
    \fcolorbox{black}{gray!10}{\parbox{0.8\textwidth}{\scriptsize Example $\pi^-\pi^+\pi^-$: s,t-channel isobars are $\sigma,f_0 (l = 0)$, $\rho (l=1)$}}
  \item Parameterizations of elastic amplitudes $t_l^{(j)}$\\
    \fcolorbox{black}{gray!10}{\parbox{0.8\textwidth}{\scriptsize Example $\pi^-\pi^+\pi^-$: $(\pi\pi)_s$-wave, $(\pi\pi)_p$-wave from K-matrix/phase shift}}
  \end{itemize}
  \vspace{0.2cm}\pause
  Result of calculation:
  \begin{itemize}
  \item Every isobar rescatters to all others. %with fixed strength 
    The solution of the equations gives {\bf shape and strength} of the ``induced'' waves.\\
    \fcolorbox{black}{gray!10}{\parbox{0.8\textwidth}{\scriptsize Example $\pi^-\pi^+\pi^-$: Even if $f_0$ is not coupled to $a_1$, 
        it will appear at final state due to rescattering}}\pause
  \item The solution is linear in production constants,
    thus we can rescatter every wave {\bf independently}.
    \fcolorbox{black}{gray!10}{\parbox{0.8\textwidth}{\scriptsize Example $\pi^-\pi^+\pi^-$: final shape and strength of $\rho$-isobar is \\
        \vspace{-0.2cm}
        $$A^{(s)}_\rho = (c_p a_\rho^{\text{direct}} + c_s a_\rho^{\text{induced}})P_l(\cos\theta_s) $$ 
        \vspace{-0.5cm}
      }}
  \end{itemize}
\end{frame}

\subsection{Example}
\begin{frame}{$(\pi\pi)_s - (\pi\pi)_p$ rescattering}
  Example: $ 0^{-} \to\pi^-\pi^-\pi^+$ system, $m_{3\pi} = 1.3\,$GeV.
  \begin{itemize}
  \item $\pi^-\pi^-$ interaction is negligible.
  \item $\pi^+\pi^-$ two main waves:  
    \begin{itemize}
    \item $(\pi\pi)_s$ I=0, i.e. {\scriptsize $f_0(500)-f_0(990)-f_0(1500)$},
    \item $(\pi\pi)_p$ I=1, i.e. {\scriptsize $\rho(770)$}.
    \end{itemize}
  \item Simple pole for $\rho$, three K-matrix poles and background for $(\pi\pi)_s$.
  \end{itemize}
  \begin{figure}[h]
    \centering
    \begin{overpic}[width=0.45\textwidth]{pict/pipiS.pdf}
      %\put(60,60) {\tiny [Kaminsky et al.]}
      %\put(60,55) {\tiny K-matrix}
    \end{overpic}\qquad
    \begin{overpic}[width=0.45\textwidth]{pict/pipiP.pdf}
      %\put(60,50) {\tiny [Kaminsky et al.]}
      %\put(60,45) {\tiny K-matrix}
    \end{overpic}
  \end{figure}
  The $(\pi\pi)_s$ K-matrix form is fitted to {\tiny \color{purple} [Kaminski et al.]} solution.
  \end{frame}

