\begin{frame}{Result}
  \vspace{-0.4cm}
  {\scriptsize
    $$A^{(s)}_{s} = (c_{s} a_{s}^{\text{direct}} + {\color{blue}c_{p}} a_{s}^{\text{induces}})P(\cos\theta_s),\qquad 
    A^{(s)}_p = (c_{p} a_{p}^{\text{direct}} + {\color{blue}c_{s}} a_{p}^{\text{induces}})P(\cos\theta_s)
    $$ 
  }
  \vspace{-0.4cm}
\begin{itemize}
\item $(\pi\pi)_p$ is the source $\Rightarrow$ $(\pi\pi)_p$ gets modified, $(\pi\pi)_s$ is induced.
    \begin{overpic}[width=0.36\textwidth]{pict/rhorho.pdf}
      \put(60,35) {\fbox{\tiny $\rho-\rho$}}
      \put(60,50) {\tiny \color{gray}Isobar amplitude}
      \put(60,45) {\tiny Rescatter amplitude}
    \end{overpic}\qquad
    \begin{overpic}[width=0.36\textwidth]{pict/rhosigma.pdf}
      \put(20,35) {\fbox{\tiny $\rho\to f_0$}}
      \put(20,50) {\tiny \color{gray}Isobar amplitude}
      \put(20,45) {\tiny Rescatter amplitude}
    \end{overpic}
\item $(\pi\pi)_s$ is the source $\Rightarrow$ $(\pi\pi)_s$ gets modified, $(\pi\pi)_p$ is induced.
  \begin{overpic}[width=0.36\textwidth]{pict/sigmarho.pdf}
    \put(60,25) {\fbox{\tiny $f_0\to\rho$}}
    \put(60,10) {\tiny \color{gray}Isobar amplitude}
    \put(60,15) {\tiny Rescatter amplitude}
  \end{overpic}\qquad
  \begin{overpic}[width=0.36\textwidth]{pict/sigmasigma.pdf}
    \put(30,40) {\fbox{\tiny $f_0 - f_0$}}
    \put(60,50) {\tiny \color{gray}Isobar amplitude}
    \put(60,45) {\tiny Rescatter amplitude}
  \end{overpic}

\end{itemize}

\end{frame}

\section{Conclusion}
\begin{frame}{Conclusion and outlook}
  Summary
  \begin{itemize}
  \item Isobar model is a rough approximation, unitarity is not satisfied.
  \item Rescattering correction can be significant.
  \item Khuri-Treiman equation gives a tool to deal with the complete series of rescattering.
  \item Khuri-Treiman Partial Wave Analysis is promising extension of PWA.    
  \end{itemize}
  \vspace{1cm}
  Perspectives:
  \begin{itemize}
  \item Generalisation of the formalism for the decay of a particle with a spin
    \begin{itemize}
    \item[$\Rightarrow$] KT-PWA. 
    \end{itemize}
  \item Implementation of formalism for coupled channels
    \begin{itemize}
    \item[$\Rightarrow$] triangle singularity mechanism. 
    \end{itemize}
  \end{itemize}

\end{frame}



