    \coordinate[right      =of b2] (c2);

    \draw[scalar] (a1) -- node[label=above:{\tiny $p_0,\,\bf s_0$} ] {} (a2); 
    \draw[scalar] (a2) -- node[label=above left:{\tiny $k_1,\,\bf m_1^2$} ] {}(b1); 
    \draw[scalar] (a2) -- node[label=below left:{\tiny $k_2,\bf m_2^2$} ] {} (b2); 
    \draw[scalar] (b1) -- node[label=right:{\tiny $k_3,\bf m_3^2$} ] {} (b2); 
    \draw[scalar] (b1) -- node[label=above:{\tiny $p_1,\,\bf s_1$} ] {} (c1); 
    \draw[scalar] (b2) -- node[label=below:{\tiny $p_2,\,\bf s_2$} ] {} (c2); 
  \end{tikzpicture}
\end{column}
\begin{column}{0.65\paperwidth}
{\small
$$
\left\{
\begin{array}{lll}
      k_i^2 = m_i^2, && i=1\dots 3, \\
      x\, k_{1\mu} - y\, k_{2\mu} + z\, k_{3\mu} = 0, && x,y,z \in [0,1], \\
      x+y+z=1,
    \end{array}
  \right.
$$
}
\end{column}
\end{columns}
\begin{itemize}
\item leading singularity: log. branching point, $A\sim \log(s-s_{\text{sing}})$,
\item square root branching points, $A\sim \sqrt{s-s_{\text{sing}}}$ (normal thresholds).
\end{itemize}
\end{frame}

