\begin{frame}[noframenumbering]{An example: deuteron size\, \textcolor{purple}{\tiny [Gribov lecture, Cambridge Univ.Pr.(2009)]}}
\begin{columns}
\begin{column}{0.5\paperwidth}
\begin{block}{Non-relativistic quantum mechanics}
Proton and neutron bound state, 
\begin{itemize}
\item binding energy: $\varepsilon = M_D - m_p - m_n$,
\item $\psi$ is the wave function,\\
 $\psi \sim e^{-r \sqrt{\varepsilon m}}.$
\item Electron scattering amplitude:\\ 
{\small $f(q)=\frac{e^2}{q^2} F(q)$}, $F(q)$ is a FF.
\item $F(q)$ is given by charge density inside of the deuteron
\end{itemize}
{\small
$F(q) = \int d^3 {\bf r} \, \psi^2(r)\, e^{i \bf q r} \approx 1 - \frac{q^2 R^2}{2} + O(q^4)$}\\
$R$ is electromagnetic radius, \\
\begin{center}
\textcolor{red}{$R^2 \sim (\varepsilon m)^{-1}$}
\end{center}
\end{block}
\end{column}
\begin{column}{0.4\paperwidth}
\begin{block}{Relativistic-theory framework}
Radius is determined by $t$-channel singularities.
