\begin{frame}[noframenumbering]{$K^\star \to K \pi$ $P$-wave decay}
\begin{itemize}
\item $P$-wave. In our parametrization:
$$
\Gamma = \frac{1}{2m_{K^\star}}\frac{1}{8\pi} \frac{2|\vec k|}{m_{K^\star}} \times 
g_{K^\star K\pi}^2 \frac{4}{3} |\vec k^2|.
$$
\item $\Gamma_{K^\star\to K\pi} = 50.8\,$MeV. So, $g_{K^\star K\pi}^2 = 31.2$.
\item From isospin $\text{Br}( K^{\star-} \to K^0 \pi^-) / \text{Br}(K^{*-} \to K^-\pi^0) = 2$.
\end{itemize}%\\[2cm]
\end{frame}

