  \begin{exampleblock}{Unitarity constaints for {\bf two-body} scattering}
    \begin{itemize}
      \item $\hat S^\dagger \hat S = \hat{\mathbb{I}}$ \quad $\hat S = \hat{\mathbb{I}} + i\hat{T}$\hfill
      $\hat{T}-\hat{T}^\dagger = i\hat{T}^\dagger\hat{T}$.
      \item $T(s,t) = \left\langle p_1'p_2'|\hat{T}|p_1p_2\right\rangle$ \hfill
      $2\textrm{Im} T(s,t) = \int \diff \Phi_2 T^*(s,t')\,T(s,t'')$
      \item Partial wave expansion $\longrightarrow$
      \item The final form\hfill $2\text{Im}\,t_l(s) = t_l^*(s)\rho(s)t_l(s)$
    \end{itemize}
  \end{exampleblock}
