\begin{frame}{Why studying charm hadrons?}{}
    \begin{columns}
        \begin{column}{0.5\textwidth}
            \begin{itemize}
                \item Two types of exotics:
                \begin{itemize}
                    \item Genuine exotics -- no convent. expected
                    \item \textbf{Mixture} -- the conventional states are influenced particle interaction.\\
                    Mass shift towards the strongly-coupled threshold.
                \end{itemize}
                \item $b/c$ hadrons are narrow
                \item Level-splitting hierarchy due to $1/m_Q$
            \end{itemize}
        \end{column}
        \begin{column}{0.48\textwidth}
