                \put(15,60) {$\lambda$-mode}
                \put(58,78) {$\rho$-mode}
            \end{overpic}
        \end{column}
        \begin{column}{0.73\textwidth}
            \begin{itemize}
                \item Heavy quark is \textbf{static} and \textbf{spinless} in the limit $m_Q\to\infty$. 
                \item Excitations of $Qqq$ are governed by the light diquark
                \item $q \uparrow^{(J^P=\frac{1}{2}^+)}$ $\otimes$ $q \uparrow^{(J^P=\frac{1}{2}^+)}$\quad$\Rightarrow$\quad$\,\underbrace{\uparrow\downarrow^{(J^P=0^+)}}_{\text{``good''}}$ and $\underbrace{\uparrow\uparrow^{(J^P=1^+)}}_{\text{``bad''}}$
                % \item $\delta E_{1^+ - 0^+} \approx 186\,$MeV~\cite{}
                \item Excitation pattern is different for ``good'' and ``bad'' diquarks
            \end{itemize}
        \end{column}
    \end{columns}
    \begin{columns}
        \begin{column}{0.24\textwidth}
            \centering
