  \coordinate[above right=of b2,xshift=2mm,label=right:$\pi^-$] (b5);
  \coordinate[right=of b4,label=right:$\pi^{-}$] (c1);
  \coordinate[above right=of b4,label=right:$\pi^{+}$] (c2);

