\begin{frame}{Approach to the rescattering using unitarity}
\begin{columns}
    \begin{column}{0.5\textwidth}
        \begin{center}
            \begin{overpic}[width=\textwidth]{pict/Xic_decay_scheme.pdf}
                \put(30,35) {\color{cola} $\updownarrow z_1\equiv\cos\theta_1$}
