            \end{overpic}
        \end{center}
    \end{column}
    \begin{column}{0.4\textwidth}
        Decay amplitude -- $\bra{p_1 p_2 p_3}\hat{T}\ket{p_0}$\\
        \begin{align*}
            \scalebox{1.5}{$\tikzprodToThree$} &=
            D_{M\lambda}^{J*}(\alpha,\beta,\gamma) F_\lambda(s,\sigma_n)\\
            &\xrightarrow[\text{scalars}]{} F(\sigma_n), \quad \sigma_n = \{\sigma_1,\sigma_2,\sigma_3\}.
        \end{align*}
    \end{column}
\end{columns}
\begin{block}{Dalitz-plot variables}
    \begin{itemize}
        \item Subchannel resonances are bands.
        \item Distribution along the bands determined by angular momenta.
        \item $\sigma_i$ is invariant mass squared, $z_i \equiv \cos\theta_{i}$ is scattering angle.
    \end{itemize}
\end{block}
\end{frame}

