\begin{frame}[noframenumbering]{Two-body unitarity and Khuri-Trieman model}
\begin{exampleblock}{Example of $f_0^{(1)}(\sigma_1)$ constraints:}
    {\scriptsize
    \begin{align*}
        f_0^{(1)}(\sigma_1) = \underbrace{\color{cola}a^{(1)}_0(\sigma_1)}_{\text{same channel}} +
                    \underbrace{
                        \int_{-1}^{1} \frac{\diff z_1}{2}
                        \left(
                            \sum_l\sqrt{2l+1} P_l(z_2) {\color{colb} a^{(2)}_l(\sigma_2)} +
                            \sum_l\sqrt{2l+1} P_l(z_3) {\color{colc} a^{(3)}_l(\sigma_3)}
                        \right)}_{\text{cross-channel(c.-c.) projections}}
    \end{align*}}
    Unitarity of $f_0^{(1)}(\sigma_1)$ -- same RHC as $2\to 2$ scattering amplitude, $\BW_0^{(1)}(\sigma_1)$
    \begin{itemize}
        \item[$\Rightarrow$] consistency relation the \textbf{direct term} and the \textbf{cross-channel projections}
        \item[$\Rightarrow$] $a^{(1)}_l(\sigma_1)$ obtains corrections from one seen in $2\to 2$.
        %  = \BW(\sigma_1)\times \underbrace{\hat{a}^{(1)}(\sigma_1)}_{\text{modification}}
    \end{itemize}
\end{exampleblock}
\end{frame}
