\newcommand{\pnumbers}[3]{\,{\tiny\begin{matrix} #1\\[-0.5mm] #2\\[-0.5mm] #3\end{matrix}}}
\begin{frame}{Partial-waves vs Isobar representation}
\begin{block}{Isobar representation}
{\scriptsize
\begin{align*}
    \tikzprodToThree &= \tikzprodUp[cola]\tikztauUpUp[cola]\pnumbers{1}{2}{3} +
                        \tikzprodDn[colb]\tikztauDnDn[colb]\pnumbers{2}{3}{1} +
                        \tikzprodDn[colc]\tikztauDnDn[colc]\pnumbers{1}{2}{3}\\
    F(\sigma_1,\sigma_2) &= F^{(1)}(\sigma_1,\sigma_2) + F^{(2)}(\sigma_1,\sigma_2) + F^{(3)}(\sigma_1,\sigma_2)\\
    &=  \sum_{l}^{{\color{red}\text{few}}} \sqrt{2l+1} P_l(z_1) {\color{cola} a^{(1)}_l(\sigma_1) } +
        \sum_{l}^{{\color{red}\text{few}}} \sqrt{2l+1} P_l(z_2) {\color{colb} a^{(2)}_l(\sigma_2) } +
        \sum_{l}^{{\color{red}\text{few}}} \sqrt{2l+1} P_l(z_3) {\color{colc} a^{(3)}_l(\sigma_3) }.
\end{align*}}
Simple \textbf{model}: $\tikzprodUp[cola]\tikztauUpUp[cola] = a^{(i)}_l(\sigma_1) \to c^{(i)} \BW(\sigma_1) = \tikzundressrightVertexUp[cola]\tikztauUpUp[cola]$.
\end{block}
\begin{block}{Partial-wave representation}
    \vspace{-3mm}
    {\scriptsize
    \begin{align*}
        \tikzprodToThree = F(\sigma_1,\sigma_2) = \sum_{l}^{{\color{red}\infty}} \sqrt{2l+1} P_l(z_1) f^{(1)}_l(\sigma_1)
    \end{align*}}\\
    \vspace{-2mm}
Why would someone do this? -- theoretical constant to $f^{(1)}(\sigma_1)$ is straightforward.
\end{block}
\end{frame}

\section{Rescattering corrections}
\begin{frame}{Two-body unitarity and KT-model}
\begin{exampleblock}{Example of $f_0^{(1)}(\sigma_1)$ constraints:}
    {\scriptsize
    \begin{align*}
        f_0^{(1)}(\sigma_1) = \underbrace{\color{cola}a^{(1)}_0(\sigma_1)}_{\text{same channel}} +
                    \underbrace{
                        \int_{-1}^{1} \frac{\diff z_1}{2}
                        \left(
                            \sum_l\sqrt{2l+1} P_l(z_2) {\color{colb} a^{(2)}_l(\sigma_2)} +
                            \sum_l\sqrt{2l+1} P_l(z_3) {\color{colc} a^{(3)}_l(\sigma_3)}
                        \right)}_{\text{cross-channel(c.-c.) projections}}
    \end{align*}}
    Unitarity of $f_0^{(1)}(\sigma_1)$ -- same RHC as $2\to 2$ scattering amplitude, $\BW_0^{(1)}(\sigma_1)$
    \begin{itemize}
        \item[$\Rightarrow$] consistency relation the \textbf{direct term} and the \textbf{cross-channel projections}
        \item[$\Rightarrow$] $a^{(1)}_l(\sigma_1)$ obtains deviations from Breit-Wigner.
        %  = \BW(\sigma_1)\times \underbrace{\hat{a}^{(1)}(\sigma_1)}_{\text{modification}}
    \end{itemize}
\end{exampleblock}
\begin{block}{KT model: analytic continuation of \textbf{two-body} unitarity}
    \begin{columns}
        \begin{column}{0.8\textwidth}
            \begin{equation*}
                \tikzprodUp[cola]\tikztauUpUp[cola]  =
                    \underbrace{\tikzundressrightVertexUp[cola]\tikztauUpUp[cola]}_{\text{source}} +
                    \underbrace{\tikzprodDn[colb]\tikztauDnDn[colb]\tikzBDnUp\tikztauUpUp[cola]+
                                \tikzprodDn[colc]\tikztauDnDn[colc]\tikzBDnUp\tikztauUpUp[cola]}_{\text{unitarization of c.-c. projections}}
            \end{equation*}
        \end{column}
        \begin{column}{0.18\textwidth}
            {\scriptsize (the loop is a dispersive integral)}
        \end{column}
    \end{columns}
\end{block}
\end{frame}

\begin{frame}{Diagramatic representation}
Isobar representation with $a_l^{(i)}(\sigma_i) = \hat{a}_l^{(i)}(\sigma_i)\,\BW_l^{(i)}(\sigma_i)$
\begin{equation*}
    \tikzprodToThree = \tikzprodUp[cola]\tikztauUpUp[cola] +
                        \tikzprodDn[colb]\tikztauDnDn[colb] +
                        \tikzprodDn[colc]\tikztauDnDn[colc].
\end{equation*}
The amplitude prefactor is not constant: $a_l^{(i)}(\sigma_i) = c_l^{i}\BW_l^{(i)}(\sigma_i) + \dots$
\begin{align*}
    \tikzprodUp[cola] \tikztauUpUp[cola]  &=
                    \tikzundressrightVertexUp[cola]\tikztauUpUp[cola] +\\
                    &\quad+
                    \tikzundressrightVertexDn[colb]\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[cola] +
                    \tikzundressrightVertexDn[colc]\tikztDnDn[colc]\tikzBsDnUp\tikztauUpUp[cola] + \\
                    &\quad+
                    \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[cola] +
                    \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colc]\tikzBsDnUp\tikztauUpUp[cola] +
                    \tikzundressrightVertexUp[colb]\tikztUpUp[colb]\tikzBUpDn\tikztDnDn[colc]\tikzBsDnUp\tikztauUpUp[cola] +
                    \tikzundressrightVertexUp[colc]\tikztUpUp[colc]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[cola] +\\
                    &\quad+
                    \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn\tikzBsDnUp\tikztauUpUp\tikzBUpDn\tikztDnDn\tikzBsDnUp\tikztauUpUp[cola] +
                    \tikzundressrightVertexUp[colb]\tikztUpUp[colb]\tikzBUpDn\tikztDnDn\tikzBsDnUp\tikztauUpUp\tikzBUpDn\tikztDnDn\tikzBsDnUp\tikztauUpUp[cola] +
                    \tikzundressrightVertexUp[colc]\tikztUpUp[colc]\tikzBUpDn\tikztDnDn\tikzBsDnUp\tikztauUpUp\tikzBUpDn\tikztDnDn\tikzBsDnUp\tikztauUpUp[cola] + \dots\\
                    &\quad+\dots\\
     \tikzprodUp[colb] \tikztauUpUp[colb]  &= \tikzundressrightVertexUp[colb]\tikztauUpUp[colb] +
                    \tikzundressrightVertexDn[colc]\tikztDnDn[colc]\tikzBsDnUp\tikztauUpUp[colb] +
                    \tikzundressrightVertexDn[cola]\tikztDnDn[cola]\tikzBsDnUp\tikztauUpUp[colb] + \dots \\
     \tikzprodUp[colc] \tikztauUpUp[colc]  &= \tikzundressrightVertexUp[colc]\tikztauUpUp[colc] +
                    \tikzundressrightVertexDn[cola]\tikztDnDn[cola]\tikzBsDnUp\tikztauUpUp[colc] +
                    \tikzundressrightVertexDn[colb]\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[colc] + \dots
\end{align*}
\end{frame}

\begin{frame}{Linearization on production coupling \paper{Aitchison (1969)}, \paper{Niecknig, Kubis (2015)}}
{Different method to group}
\begin{align*}
    \text{direct term}: &&\tikzundressrightVertexUp[cola]\!\left[\dots\right]\!\tikztauUpUp[cola] &=
        \overbrace{
            \tikzundressrightVertexUp[cola]\tikztauUpUp[cola]}^{\text{c\,\BW}} +
        \overbrace{
            \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[cola] +
            \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colc]\tikzBsDnUp\tikztauUpUp[cola] +
            \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[colc]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[cola] + \dots
        }^{\text{small corrections to lineshape}}\\
    \text{induced term}: &&\tikzundressrightVertexUp[cola]\!\left[\dots\right]\!\tikztauUpUp[colb] &=
        \underbrace{
            \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colc]\tikzBsDnUp\tikztauUpUp[colb] +
            \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[colc]\tikzBUpDn\tikztauDnDn[colb] +
            \tikzundressrightVertexUp[cola]\tikztUpUp[cola]\tikzBUpDn\tikztDnDn[colb]\tikzBsDnUp\tikztauUpUp[colc]\tikzBUpDn\tikztDnDn[cola]\tikzBsDnUp\tikztauUpUp[colb] + \dots
        }_{\text{rescattering reflection}}
\end{align*}
\begin{columns}
    \begin{column}{0.53\textwidth}
        \begin{align*}
            \tikzprodToThree &=
                \overbrace{
                    \tikzundressrightVertexUp[cola]\!\left[\dots\right]\!\tikztauUpUp[cola]}^{\text{direct}} +
                 \overbrace{
                    \tikzundressrightVertexUp[cola]\!\left[\dots\right]\!\tikztauUpUp[colb] +
                    \tikzundressrightVertexUp[cola]\!\left[\dots\right]\!\tikztauUpUp[colc]}^{\text{induced}} \\
                &\quad +
                \tikzundressrightVertexUp[colb]\!\left[\dots\right]\!\tikztauUpUp[cola] +
                   \tikzundressrightVertexUp[colb]\!\left[\dots\right]\!\tikztauUpUp[colb] +
                   \tikzundressrightVertexUp[colb]\!\left[\dots\right]\!\tikztauUpUp[colc] \\
                &\quad +
                \underbrace{
                    \tikzundressrightVertexUp[colc]\!\left[\dots\right]\!\tikztauUpUp[cola] +
                    \tikzundressrightVertexUp[colc]\!\left[\dots\right]\!\tikztauUpUp[colb]}_{\text{induced}} +
                \underbrace{
                   \tikzundressrightVertexUp[colc]\!\left[\dots\right]\!\tikztauUpUp[colc]}_{\text{direct}} \\
        \end{align*}
    \end{column}
    \begin{column}{0.46\textwidth}
        \begin{itemize}
            \item Every isobar generates others
            \item Model is still linear on isobar couplings
            \item $N$ isobars $\Rightarrow$ $N$ Dalitz-plots amplitudes (direct+induced)
        \end{itemize}
    \end{column}
\end{columns}
\end{frame}

