    \begin{block}{Probability conservation on partial waves}
        \begin{align*}
            \text{condition on }f_0^{(1)}(\sigma_1) &\Rightarrow
            {\scriptsize
                \underbrace{a^{(1)}_0(\sigma_1)}_{\text{same channel}}
                    \leftrightarrow
                \underbrace{
                    \int_{-1}^{1} \frac{\diff z_1}{2}
                    \left(
                        \sum_l\sqrt{2l+1} P_l(z_2) a^{(2)}_l(\sigma_2) +
                        \sum_l\sqrt{2l+1} P_l(z_3) a^{(3)}_l(\sigma_3)
                    \right)}_{\text{cross-channel(c.-c.) projections}}
        }\end{align*}
        \vspace{-2mm}
    \begin{itemize}
        \item Induced part is limited by the cross-channel projections!
    \end{itemize}
    \end{block}
\end{frame}

