\begin{frame}{Summary}
    \begin{block}{Phenomenon of the final-state interaction}
        \begin{itemize}
            \item is an integral part of hadronic interaction
            \item is a non-perturbative effect
        \end{itemize}
    \end{block}
    \begin{block}{Khuri-Trieman model}
        \begin{itemize}
            \item is a method to constraint the rescatteing using on the cross-channel projection
            \item based on the two-body unitairty and exploits dispersive relation
            \item naturally incorporates triangle singularities.
        \end{itemize}
    \end{block}
    \begin{exampleblock}{In practice}
        \begin{itemize}
            \item Successfully applied on light-meson decays
            \item Showed to work for elastic region of $D$ decay
            \item Gives a way to estimate an effect of Triangle Singularity for exotic sector.
        \end{itemize}
    \end{exampleblock}
\end{frame}


