\section{Three-particle scattering}

\begin{frame}[noframenumbering]{}{}
\begin{center}
{\Huge Three-particle scattering}
\end{center}
\vspace{1cm}
\hfill Three-body unitarity, Ladders and Resonances, short-range factorization\\
\hfill \paper{arXiv:1904.11894}
\end{frame}

\begin{frame}{Decomposition of the $3\to 3$ scattering}
\begin{itemize}\pause
    \item \textbf{Particle pairing} (symmetrization or isobar decomposition),\\
    e.g. for the state of identical particles:\
    {\scriptsize
    \begin{align*}
    \ket{p_1 p_2 p_3} &= \frac{1}{3!}\left(\ket{p_1}\otimes\ket{p_2}\otimes\ket{p_3}+\textrm{symm.}\right)\\
                      &=\frac{1}{3}\sum_{a=1}^{3}\ket{p_{a_1}}\frac{\ket{p_{a_2}}\otimes\ket{p_{a_3}} + \ket{p_{a_3}}\otimes\ket{p_{a_2}}}{2} = \frac{1}{3}\sum_{a=1}^3\ket{a} \quad
                      \text{-- isobar-spectator states},
    \end{align*}}\pause
    \item Separation of \textbf{connected} and \textbf{disconnected} terms (LSZ reduction):
    {\scriptsize
    \begin{align*}
      \tikzdiagThreeToThree &\,=\, \sum_{9}\left(3\,\tikztauUpUp + \tikzconUpUpFULL\right)
    \end{align*}}\pause
    \item Partial wave \textbf{expansion} (spin $l$ in subchannels, spin $j$ overall)\pause
    \item \textbf{Amputation} of the last scattering bit
    {\scriptsize
    \begin{align*}
      \tikztauUpUp\, &= t(\sigma),\\
      \tikzconUpUpFULL \equiv \tikztauUpUp\tikzconUpUp\tikztauUpUp &= t(\sigma')\,\Tcal(\sigma',s,\sigma)\,t(\sigma),
    \end{align*}}
\end{itemize}
\end{frame}
% 1904.11894
\begin{frame}{Three-body-unitarity constraint\hfill\paper{G.Fleming, Phys.Rev. 135 (1964)}}
{Three-body scattering amplitude must satisfy the integral equation}
{\scriptsize
  \begin{align*}
  &\Tcal(\sigma',s,\sigma)-\Tcal^\dagger(\sigma',s,\sigma) =
  & \tikzconUpUp - \tikzconUpUp^{\,\,\dagger} =
  \\
    &\qquad 2i\, \frac{1}{\lamHs(\sigma')} \frac{1}{8\pi}\int_{\sigma^-(\sigma',s)}^{\sigma^+(\sigma',s)} \diff\sigma_3'\,t(\sigma_{3}') \Tcal(\sigma_{3}',s,\sigma)
    && \tikzDnUp\tikztauUpUp\tikzconUpUp\\
  %
  &\qquad +\frac{i}{3}\,\int_{4\mpisq}^{(\sqrt{s}-\mpi)^2}  \frac{\diff \sigma''}{2\pi} \Tcal^\dagger(\sigma',s,\sigma'') \,t(\sigma'')t^\dagger(\sigma'') \,
    \rho(\sigma'')\rho_s(\sigma'')\,\Tcal(\sigma'',s,\sigma)
    &\tikzconUpUp\tikztauUpUp&\tikzCUpUp\tikztauUpUp\tikzconUpUp \\
  %
  &\qquad + \frac{2i}{3}\,\frac{1}{(8\pi)^2}\iint_{\phi(\sigma_2'',s,\sigma_3'')>0}  \frac{\diff \sigma_2''\diff \sigma_3''}{2\pi s}\,
          \Tcal^\dagger\,(\sigma',s,\sigma_{2}'') t^\dagger\,(\sigma''_{2})t(\sigma''_{3}) \Tcal(\sigma_{3}'',s,\sigma)
  &\tikzconUpDn\tikztauDnDn&\tikzDnUp\tikztauUpUp\tikzconUpUp \\
  %
  &\qquad + 2i\, \frac{1}{\lamHs(\sigma)} \frac{1}{8\pi}\int_{\sigma^-(\sigma,s)}^{\sigma^+(\sigma,s)} \diff\sigma_2\, \Tcal^\dagger(\sigma',s,\sigma_{2}) t^\dagger(\sigma_{2})
  &\tikzconUpDn\tikztauDnDn&\tikzDnUp \\
  %
  &\qquad + 6i\,\frac{2\pi s}{\lamHs(\sigma')\lamHs(\sigma)} \,\theta^+(\phi(\sigma',s,\sigma)).
  && \tikzDnUp
\end{align*}
}
% \end{subequations}
% }
In a short form: \paper{Aaron-Amada(TCP 2 (1977)), Mai et al.(EPJ A53 (2017)), Jackura et al.(EPJ C79 (2019))}:
% \small
\begin{equation*}
  \Tcal - \Tcal^\dagger = \dB\tau\Tcal + \Tcal^\dagger(\tau-\tau^\dagger)\Tcal + \Tcal^\dagger\tau^\dagger\dB\tau\Tcal + \Tcal^\dagger\tau^\dagger\dB + \dB,
\end{equation*}
\end{frame}

\begin{frame}{Splitting amplitude by the interaction range}{}
    % {\scriptsize
    \begin{align*}
      \tikzconUpUp && \Tcal(\sigma',s,\sigma) &= \Ladder(\sigma',s,\sigma)+\Rcal(\sigma',s,\sigma).&&\tikzLUpUp + \tikzRUpUp
  \end{align*}%}
 \vspace{-3mm}
\begin{block}{Long-range part: exchange processes (on-shell) \paper{Mai et al.(EPJ A53 (2017))}}
    \begin{itemize}
        \item Infinite sum of the one-particle-exchange process
        {\scriptsize
        \begin{align*}
          \tikzLUpUp && \Ladder    & = \Ker + \Ladder\tau\Ker = \Ker + \Ker \tau \Ladder. && \tikzBUpDn+\tikzLUpUp\tikztauUpUp\tikzBUpDn
      \end{align*}}
      \item $\Tcal = \Ladder$, $\Rcal=0$ already satisfy unitarity. Can it have resonances?
    \end{itemize}
\end{block}
\begin{exampleblock}{Short-range part: resonances \paper{MM, Y.Wunderlich, et al. (JPAC) 1904.11894}}
\begin{itemize}
    \item Condition for $\Rcal(\sigma',s,\sigma)$ is complicated
    \item However, simplified significantly if FSI is factorized from both sides:
    {\scriptsize
    \begin{align*}
      \tikzRUpUp && \Rcal & \equiv  (1+\Ladder\tau)\, \RcalHat\, (\tau\Ladder+1).&&
      \left(\tikzoneUpUp + \tikzLUpUp\tikztauUpUp \right)\tikzRhatUpUp\left(\tikztauUpUp\tikzLUpUp + \tikzoneUpUp\right),
  \end{align*}}
\end{itemize}
\end{exampleblock}

\end{frame}

\begin{frame}{Unitarity constraint for the resonance kernel}{}
Familiar form of the constraint {\scriptsize(see two-body constraint at slide 4)}:
\begin{align*}
   \RcalHat-\RcalHat^\dagger &= \RcalHat^\dagger
   (1+\tau^\dagger \Ladder^\dagger)
   \left[
   \tau-\tau^\dagger + \tau^\dagger\dB \tau
   \right](1+\Ladder \tau )
   \, \RcalHat\\
   &= \RcalHat^\dagger
   \left[
   \tau-\tau^\dagger + \tau \Ladder \tau - \tau^\dagger\Ladder^\dagger \tau^\dagger
   \right]
   \, \RcalHat.
\end{align*}
\vspace{-3mm}
\begin{exampleblock}{}
\begin{itemize}\pause
    \item K-matrix-like solution {\scriptsize(\cf $K_\text{d.f.}$ \paper{M.Hansen, S.Sharpe, PRD90 (2014), 116003})}
    {\scriptsize
    \begin{align*}
        \RcalHat &= \Kmat + \Kmat(\tau + \tau\Ladder\tau)\,\RcalHat\\
        & = \Kmat + \Kmat(\tau + \tau\Ladder\tau)\Kmat + \Kmat(\tau + \tau\Ladder\tau)\Kmat(\tau + \tau\Ladder\tau)\Kmat + \dots\\
        & = \tikzundressVertexUpUp + \tikzundressVertexUpUp\tikztauUpUp\tikzLUpUp\tikztauUpUp\tikzundressVertexUpUp +
        \tikzundressVertexUpUp\tikztauUpUp\tikzLUpUp\tikztauUpUp\tikzLUpUp\tikztauUpUp\tikzundressVertexUpUp + \dots
    \end{align*}}\pause
    \vspace{-3mm}
    \item Rescattering interpretation \paper{MM, Y.Wunderlich, et al. (JPAC) 1904.11894}:
    {\scriptsize
    \begin{align*}
        \RcalHat-\RcalHat^\dagger = &
        \underbrace{
            \RcalHat^\dagger (1+\tau^\dagger \Ladder^\dagger)
        }_{\text{rescattering}}
        %
        \overbrace{
            \left[
                \tau-\tau^\dagger + \tau^\dagger\dB \tau
            \right]
        }^{\text{direct+crossed\,coupling}}
        %
        \underbrace{
            (1+\Ladder \tau )\, \RcalHat
        }_{\text{rescattering}}
        \quad\xrightarrow[\text{sort-of}]{}\quad
        \tikzdressedrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzdressedleftVertexUp +
        \tikzdressedrightVertexUp\tikztauUpUp\tikzUpDn\tikztauDnDn\tikzdressedleftVertexDn
    \end{align*}}
\end{itemize}
\end{exampleblock}
\end{frame}

\begin{frame}{Factorization of the resonance kernel }
    \begin{itemize}
        \item Strictly, one more (weak) assumption -- \textbf{Factorization}
    \end{itemize}
    {\scriptsize
    \begin{align*}
       \RcalHat(\sigma',s,\sigma) &= k_f(\sigma')\RcalFac(s)\,\,k_i(\sigma)\,\,\text{ OR }\\ &=\RcalFac_{00}(s)+\sigma'\RcalFac_{10}(s)+\RcalFac_{01}(s)\sigma+\sigma'\RcalFac_{11}(s)\sigma+\dots,
   \end{align*}}
   $\Rightarrow$\,\,Unitarity requirement is algebraic!
   {\scriptsize
   \begin{align*}
      \RcalFac(s)-\RcalFac^\dagger(s) &= i\,\RcalFac^\dagger(s) \Sigma(s) \,\RcalFac(s),
  \end{align*}}
  \vspace{-7mm}
   {\scriptsize
   \begin{align*}
     \text{with}\qquad\DressedRho &\equiv
       \Kcal^\dagger(\tau-\tau^\dagger)\Kcal
       + \Kcal^\dagger \tau^\dagger\dB \tau\Kcal,
       &&
       \tikzdressedrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzdressedleftVertexUp +
       \tikzdressedrightVertexUp\tikztauUpUp\tikzUpDn\tikztauDnDn\tikzdressedleftVertexDn
   \end{align*}}
   % \\[-15mm]
   $\Kcal$ is the modification of the isobar lineshape due to the rescattering\pause
    \begin{columns}
       \begin{column}{0.48\textwidth}
           \begin{block}{An approximate-three-body unitarity}
           {\scriptsize
           \begin{align*}
               \RcalFac(s) = \frac{g^2}{m^2-s-ig^2/2 \left[\scalebox{0.6}{\parbox{0.6\textwidth}{
               $\tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp +
            \tikzundressrightVertexUp\tikztauUpUp\tikzUpDn\tikztauDnDn\tikzundressleftVertexDn$}}\right]}
            \end{align*}
            contains effect of the subchannel-resonances \textbf{interference}}
            \end{block}
       \end{column}
       \begin{column}{0.48\textwidth}
           \begin{exampleblock}{The quasi-two-body approximation}
           {\scriptsize
           \begin{align*}
               \RcalFac(s) = \frac{g^2}{m^2-s-ig^2/2 \left[\scalebox{0.6}{\parbox{0.3\textwidth}{
               $\tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp$}}\right]}
        \end{align*}
        naively accounts for the subchannel-resonance decay
        }
        \end{exampleblock}
       \end{column}
   \end{columns}
   \only<2>{
   \begin{textblock*}{8cm}(9cm,6.3cm)
       \paper{J.Basdevant, Ed Berger, PRD19 (1979) 239}
   \end{textblock*}}
\end{frame}

