\begin{frame}{Fit Model}
  Fit three waves simultaneously:
  \begin{enumerate}
    \item $\rhoSwave\ \,\Rightarrow\ a_1(1260)$
    \item $\fnotPwave\ \Rightarrow\ a_1(1420)$ or triangle
    \item $\rhoDwave\ \,\Rightarrow\ a_2(1320)$\\[5mm]
  \end{enumerate}
  \pause
  Separate matrix element: $\M_{tot} = \M_\text{sig} + \M_\text{bgd}$
  \begin{equation*}
    \M_\text{sig} = A\cdot\text{BW}_X \left[ \sum \Delta \right]
  \end{equation*}
  \begin{equation*}
     \M_\text{bgd} = a \cdot \left( \frac{m_{3\pi} - \SI{0.5}{\GeV}}{\SI{0.5}{\GeV}} \right)^b \cdot \exp\left(c(t^\prime) \tilde{p}^2\right)
  \end{equation*}
\pause
\begin{equation*}
  \text{Intensity} = m_{3\pi} \abs{\M_\text{tot}}^2 \tilde{\Phi}_2^\xi
\end{equation*}
\end{frame}

