\section{Introduction}

\subsection{S-matrix and Unitarity}
\begin{frame}{Analytic structure: resonance is a pole of amplitude}
  \begin{block}{\textbf{$S$-matrix theory} --- list of general constraints}
    \begin{columns}
      \begin{column}{0.3\textwidth}
            \includegraphics[width=\textwidth]{in-line-figures/scattering.pdf}
      \end{column}
      \hspace{-5mm}
      \begin{column}{0.68\textwidth}
        \begin{itemize}
            \item Scattering \textbf{amplitude} (a function) is the main object of the theory.
            \item Requirements: analyticity, \textbf{unitarity}, Lorentz-invariance, \dots
        \end{itemize}
      \end{column}
    \end{columns}
  \end{block}\pause
  \begin{exampleblock}{Resonances = Poles at the complex plane}
    \vspace{-2mm}
    \begin{columns}
      \begin{column}{0.35\textwidth}
        \begin{overlayarea}{\textwidth}{0.4\textheight}
            \only<2>{\includegraphics[width=\textwidth]{pict/sheet_0.pdf}}
            \only<3>{\includegraphics[width=\textwidth]{pict/sheet_1.pdf}}
            \only<4>{\includegraphics[width=\textwidth]{pict/sheet_2.pdf}}
        \end{overlayarea}
      \end{column}
      \begin{column}{0.6\textwidth}
        Features of the complex $s$ plane:
        \begin{itemize}
          \item $s=E^2$ -- the total inv.mass squared
          \item The real axis $\to$ physical world
          \item The imaginary axis $\to$ analytical continuation
        \end{itemize}
      \end{column}
    \end{columns}
    \vspace{-2mm}
  \end{exampleblock}%\pause\pause
  % \begin{block}{Unitarity constraints for {\bf two-body} scattering}
  %   \begin{itemize}
