\begin{frame}{Approach to the rescattering using unitarity\hfill\paper{see Tobias talk}}
\begin{columns}
    \begin{column}{0.5\textwidth}
        \begin{center}
            \begin{overpic}[width=\textwidth]{pict/Xic_decay_scheme.pdf}
                \put(30,35) {\color{cola} $\updownarrow z_1\equiv\cos\theta_1$}
                \put(40,27) {\color{colc} $\leftrightarrow z_3\equiv\cos\theta_3$}
                % \put(35,45) {\color{colb} $z_2\equiv\cos\theta_3$}
            \end{overpic}
        \end{center}
    \end{column}
    \begin{column}{0.4\textwidth}
        Decay amplitude -- $\bra{p_1 p_2 p_3}\hat{T}\ket{p_0}$\\
        \begin{align*}
            \scalebox{1.5}{$\tikzprodToThree$} &=
            D_{M\lambda}^{J*}(\alpha,\beta,\gamma) F_\lambda(s,\sigma_n)\\
            &\xrightarrow[\text{scalars}]{} F(\sigma_n), \quad \sigma_n = \{\sigma_1,\sigma_2,\sigma_3\}.
        \end{align*}
        \hfill\paper{MM et al. (JPAC), arXiv:1910.04566}
    \end{column}
\end{columns}
\begin{block}{Dalitz-plot variables}
    \begin{itemize}
        \item Subchannel resonances are bands.
        \item Distribution along the bands determined by angular momenta.
        \item $\sigma_i$ is invariant mass squared, $z_i \equiv \cos\theta_{i}$ is scattering angle.
    \end{itemize}
\end{block}
\end{frame}

\newcommand{\pnumbers}[3]{\,{\tiny\begin{matrix} #1\\[-0.5mm] #2\\[-0.5mm] #3\end{matrix}}}
\begin{frame}{Rescattering corrections and KT--equations}
\begin{block}{Isobar representation}
{\scriptsize
\begin{align*}
    \tikzprodToThree &= \tikzprodUp[cola]\tikztauUpUp[cola]\pnumbers{1}{2}{3} +
                        \tikzprodDn[colb]\tikztauDnDn[colb]\pnumbers{2}{3}{1} +
                        \tikzprodDn[colc]\tikztauDnDn[colc]\pnumbers{1}{2}{3}\\
    F(\sigma_n) &= F^{(1)}(\sigma_n) + F^{(2)}(\sigma_n) + F^{(3)}(\sigma_n)\\
    &=  \sum_{l}^{{\color{red}\text{few}}} \sqrt{2l+1} P_l(z_1) {\color{cola} a^{(1)}_l(\sigma_1) } +
        \sum_{l}^{{\color{red}\text{few}}} \sqrt{2l+1} P_l(z_2) {\color{colb} a^{(2)}_l(\sigma_2) } +
        \sum_{l}^{{\color{red}\text{few}}} \sqrt{2l+1} P_l(z_3) {\color{colc} a^{(3)}_l(\sigma_3) }.
\end{align*}}
\\\vspace{-2mm}
Simple \textbf{model}: $\tikzprodUp[cola]\tikztauUpUp[cola] = a^{(i)}_l(\sigma_1) \to c^{(i)} \BW(\sigma_1) = \tikzundressrightVertexUp[cola]\tikztauUpUp[cola]$.
\end{block}\pause
\vspace{-2mm}
\begin{block}{Partial-wave representation}
  \vspace{-5mm}
  \begin{columns}
    \begin{column}{0.8\textwidth}
      \begin{align*}
          \tikzprodToThree = F(\sigma_n) = \sum_{l}^{{\color{red}\infty}} \sqrt{2l+1} P_l(z_1) f^{(1)}_l(\sigma_1)
      \end{align*}
    \end{column}
      \hspace{-5mm}
