\section{Triangle diagram}
\subsection{Calculation}
\begin{frame}{Triangle diagram}
\begin{exampleblock}{Dispersion integral}
  $$
  \tikzprodUp[colb]\tikztauUpUp[colb]\tikzBUpDn\tikztauDnDn[cola] = \frac{\color{cola}t(\sigma)}{2\pi} \int_{\sigma_\text{th}}^{\infty} \frac{{\color{colb}b(\sigma')\rho(\sigma')}}{\sigma'-\sigma} \diff \sigma' ,\qquad
  {\color{colb}b(\sigma')} = \int_{-1}^{1} \frac{\diff z}{2} {\color{colb}a(\sigma''(z))}
  $$
\end{exampleblock}\pause
\begin{block}{Feynman integral}
  \vspace{-1mm}
  $$
  \raisebox{-0.45\height}{\includegraphics[scale=0.8]{pict/triangle_thick_resonance_Schmid_col.pdf}} =
  {\color{cola}t(\sigma)} \int \frac{\mathrm{d} k^4 }{(2\pi)^4\, i} \frac{1}
   {\Delta_1 \Delta_2 {\color{colb}\Delta_3}}, \quad \Delta_i = m_i^2 - k_i^2 - i\epsilon
  $$\\  \vspace{-1mm}
  Gives identical expression as the dispersion integral (S-wave, narrow resonance)
\end{block}\pause
% \vspace{2mm}
\begin{alertblock}{Known properties of the triangle diagram \paper{Landau (1959), Cutkosky(1960)}:}
  \begin{itemize}
    \item Loop integral in convergent (scalar theory)
    \item except a finite set of singularities points (Landau surphase)
    \item singular behavior $\sim \log(s-s_0)$
    \item $s_0$ is determined by masses of particles, external invariants.
  \end{itemize}
\end{alertblock}
\end{frame}


