\begin{frame}{CP violation in hadronic decays}
  \begin{columns}
    \begin{column}{0.33\textwidth}
      \centering
        CPV is well seen in $B\to hhh$:
        \begin{overpic}[width=\textwidth]{Fig3c.pdf}
            \put(44,16) {$B\to\pi\pi\pi$}
        \end{overpic}
        \begin{overpic}[width=\textwidth]{Fig3d.pdf}
            \put(44,45) {$B\to\pi K\bar{K}$}
        \end{overpic}
        \paper{PRD 90, 112004 (2014)}
    \end{column}
    \begin{column}{0.35\textwidth}
      \centering
        Appearance of CPV effects:
        \vspace{-3mm}
        {\small
        \begin{align*}
            B\to f :\quad & A = \sum_i |A_i| e^{i(\delta_i+\phi_i)}\\
            \overline{B}\to \overline{f} :\quad & \overline{A} = \sum_i |A_i| e^{i(\delta_i-\phi_i)},
        \end{align*}}
        \vspace{-3mm}
        \begin{itemize}
            \item Strong phase ($\delta$) does not change under CP,
            \item Weak phase ($\phi$) flip the sign.
        \end{itemize}
        {\small
        \begin{multline*}
            \mathcal{A}_\text{CP} = \frac{|A|^2-|\overline{A}|^2}{|A|^2+|\overline{A}|^2}\\ \scriptsize
            \to \sum_i |A_i| |A_j| \sin(\delta_i-\delta_j) \sin(\phi_i-\phi_j)
        \end{multline*}}
    \end{column}
    \begin{column}{0.25\textwidth}
      \begin{alertblock}{      \centering
        NOTHING \\in baryonic decays}{}
        \centering
        \textbf{In $\Lb$ decay:}
        \begin{itemize}
          \item $pK^-$, $p\pi^-$,\\$K_S^0 p\pi^-$, $\Lambda K^-K^+$
          \item $p\pi^-\pi^-\pi^+$,\\$p\pi^-K^-K^+$,\\$pK^-\pi^+\pi^+$,\\$pK^-K^+K^+$
        \end{itemize}
        \textbf{In $\Xi_b^-$ decay:}
        \begin{itemize}
          \item $pK^-\pi^+\pi^+$,\\$pK^-\pi^+K^+$
        \end{itemize}          
      \end{alertblock}
      \begin{itemize}
        \item[{\color{red}$?$}] {\large\fbox{$pK^-K^-$}}
      \end{itemize}
  \end{column}
  \end{columns}
\end{frame}

