    \paper{\large LHCb, JHEP 06 (2020) 136}
  \end{center}
\end{frame}

\begin{frame}{Excited $\Lambda_b$ resonances}
  {Spectroscopy of the good diquark}
  \centering
  \begin{overpic}[width=0.5\textwidth]{Lb_spectrum.pdf}
    \put(30,17) {\paper{\tiny LHCb, PRL 109 (2012) 172003}}
    \put(65,50) {\paper{\tiny LHCb, PRL 122 (2019) 012001}}
    \put( 5,45) {\paper{\tiny LHCb, JHEP 06 (2020) 136}}
  \end{overpic}\\\vspace{5mm}
  Diquark picture, $Q(qq)$ with $(qq)$ having $J^P = 0^+$, works very well for observed-so-far states.
\end{frame}

\begin{frame}{$\Lb \pi^+\pi^- $ spectrum\hfill \paper{LHCb, JHEP 06 (2020) 136}}
  \begin{columns}
    \begin{column}{0.48\textwidth}
      Low-mass part of the spectrum\\
      \includegraphics[width=\textwidth]{Fig_5_cleaned.pdf}
    \end{column}
    \begin{column}{0.48\textwidth}
      High-mass part of the spectrum\\
      \includegraphics[width=\textwidth]{Fig_2_no_total.pdf}
    \end{column}
  \end{columns}
  The broad structure:
  \begin{itemize}
    \item An elastic resonance in a system $\Lb \pi^+\pi^-$
    \item Three coupled quasi-stable channels: $\Lb f_0$, $\Sigma_b^{\pm}\pi^{\mp}$, and $\Sigma_b^{*\pm}\pi^{\mp}$
  \end{itemize}
  $\Rightarrow$ an excellent opportunity to explore the three-body unitarity
\end{frame}

\begin{frame}{Three-body unitarity constraint}
  \begin{columns}
    \begin{column}{0.6\textwidth}
      Unitairity equation for the reduced amplitude
      \includegraphics[width=\textwidth]{unitirity_equation.png}
    \end{column}
    \begin{column}{0.4\textwidth}
      Three-main aspects:
      \begin{itemize}
        \item Two-body {\color{cola} rescattering} effects\\
        \quad influence of subchannel resonances to each-other lineshape
        \item Genuine three-to-three dinamics, {\color{cola} generated states (the ladder)}
        \item[o] Lineshape of the {\color{cola} regular states} decaying to three particles
      \end{itemize}
    \end{column}
  \end{columns}
  \small
  Related works:
  \begin{itemize}
    \item \paper{Mai et al., EPJA 53 (2017) 9, 177}
    \item \paper{Jackura et al.(JPAC), EPJC 79 (2019) 1, 56}\\
    \item \paper{MM et al.(JPAC), JHEP 08 (2019) 080}
  \end{itemize}
\end{frame}

\begin{frame}{Unitairy resonance kernel\hfill \paper{MM et al.(JPAC), JHEP 08 (2019) 080}}{}
  \begin{columns}
    \begin{column}{0.13\textwidth}
      \rotatebox{90}{
        \parbox{\textwidth}{
          \begin{alertblock}{}{}
            \centering
            side\\
            reminder
          \end{alertblock}
        }
      }
    \end{column}
    \begin{column}{0.8\textwidth}
      \begin{itemize}
        \item A two-body resonance amplitude
      \end{itemize}
      \begin{align*}
        \RcalFac(s) = \frac{g^2}{m^2-s-im\Gamma(s)} = \frac{g^2}{m^2-s-ig^2\Phi_2(s)/2}
      \end{align*}
      $\Phi_2(s)$ is a two-body phase-space
    \end{column}
  \end{columns}
  % \begin{itemize}
  %   \item An amplitde for a resonance in three-body system
  % \end{itemize}
  \begin{exampleblock}{\centering A resonance in three-body system}{}
  \begin{columns}
     \begin{column}{0.48\textwidth}
      \textbf{An approximate-three-body unitarity}\\
        %  \begin{block}{}
         {\scriptsize
         \begin{align*}
             \RcalFac(s) = \frac{g^2}{m^2-s-ig^2/2 \left[\scalebox{0.6}{\parbox{0.6\textwidth}{
             $\tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp +
          \tikzundressrightVertexUp\tikztauUpUp\tikzUpDn\tikztauDnDn\tikzundressleftVertexDn$}}\right]}
          \end{align*}
          contains effect of the subchannel-resonances \textbf{interference}}
          % \end{block}
     \end{column}
     {\Huge $|$}
     \begin{column}{0.48\textwidth}
      \textbf{The quasi-two-body approximation}\\
        %  \begin{exampleblock}{The quasi-two-body approximation}
         {\scriptsize
         \begin{align*}
             \RcalFac(s) = \frac{g^2}{m^2-s-ig^2/2 \left[\scalebox{0.6}{\parbox{0.3\textwidth}{
             $\tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp$}}\right]}
      \end{align*}
      naively accounts for the subchannel-resonance decay
      }
      % \end{exampleblock}
     \end{column}
   \end{columns}
   \vspace{4mm}
   \scriptsize
   \centering
   + dispersion integral to ensure analytic structure (important close to threshold)
  \end{exampleblock}

  %  \begin{textblock*}{8cm}(9cm,6.3cm)
  %      \paper{J.Basdevant, Ed Berger, PRD19 (1979) 239}
  %  \end{textblock*} 
\end{frame}

