\newcommand{\chtwo}{\ensuremath{\Sigmabpm \pi^{\mp}}}
\newcommand{\chthr}{\ensuremath{\SigmabXpm \pi^{\mp}}}
\newcommand{\redbar}{{\color{red}|}}
\begin{frame}{Appliction to $\Lb \pi^+ \pi^-$. Self-energy function }{}
  % The case of three channels:
  % \begin{itemize}
  %   \item align
  % \end{itemize}
  % Quasi-two-body phase space factors:
  \vspace{-3mm}
  {\scriptsize
    \begin{align*}
    \rho(s) &= \tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp +
    \tikzundressrightVertexUp\tikztauUpUp\tikzUpDn\tikztauDnDn\tikzundressleftVertexDn\\
    &=
    \begin{pmatrix}
      g_{\chone}\\
      g_{\chtwo}\\
      g_{\chthr}
    \end{pmatrix}^\dagger
    \begin{pmatrix}
      \chone\redbar\chone & \chone\redbar\chtwo & \chone\redbar\chthr \\
      \chtwo\redbar\chone & \chtwo\redbar\chtwo & \chtwo\redbar\chthr \\
      \chthr\redbar\chone & \chthr\redbar\chtwo & \chthr\redbar\chthr 
    \end{pmatrix}
    \begin{pmatrix}
      g_{\chone}\\
      g_{\chtwo}\\
      g_{\chthr}
    \end{pmatrix}
  \end{align*}}
  \begin{columns}
    \begin{column}{0.5\textwidth}
      \includegraphics[width=\textwidth]{qtb_phase_space.PNG}
    \end{column}
    \begin{column}{0.45\textwidth}
      \vspace{-3mm}
      $$\sim
      \sqrt{\scalebox{0.5}{
      \parbox{0.3\textwidth}{
        $\tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp$
      }}}
      \begin{pmatrix}
        1 & z & z_* \\
        \cdot & 1+y & x \\
        \cdot & \cdot & 1+y_*
      \end{pmatrix}
      \sqrt{\scalebox{0.5}{
        \parbox{0.3\textwidth}{
          $\tikzundressrightVertexUp\tikztauUpUp\tikzCUpUp\tikztauUpUp\tikzundressleftVertexUp$
        }}}
      $$
      with 
      $x(m^2) = -0.014 +0.004i$\\
      $z(m^2) = -0.05 - 0.12i$, $z_*(m^2) = -0.01 - 0.07i$,\\
      $y(m^2) = 0.003$, and\\
      $y_*(m^2) = -0.02$\\
      \quad $\Rightarrow$ \textbf{rescattering effects are negligible}
    \end{column}
  \end{columns}
\end{frame}

\begin{frame}{Fit to the data}{\paper{LHCb, JHEP 06 (2020) 136}}
  \begin{columns}
    \begin{column}{0.44\textwidth}
      Parameters of the new $\Lb(6072)$:
      \begin{align*}
        m &= 6072.3 \pm  2.9 \pm  0.6 \pm  0.2\,\mathrm{MeV}\\
        \Gamma &= 72 \pm  11 \pm  2 \,\mathrm{MeV}
      \end{align*}
      Advance parametrization impacts the width measurement
      with respect to the naive BW\\
      \vspace{1cm}
      \begin{block}{}
        Framework works
        $\Rightarrow$ move to complex examples $X\to D\bar{D}\pi(\gamma)$
      \end{block}
    \end{column}
    \begin{column}{0.55\textwidth}
      \vspace{-5mm}
      \includegraphics[width=\textwidth]{Fig_2.pdf}
    \end{column}
  \end{columns}
\end{frame}

\begin{frame}{Summary}{}
  Amplitude analysis is a critical tool for the further progress
  \begin{block}{}
    Three parts of the three-body problem:
    \begin{itemize}
      \item 3b dynamics -- \textbf{3b unitarity}
      \item Angular analysis of the decay -- \textbf{Dalitz-Plot decomposition}
      \item Two-body dynamics on the Dalitz -- \textbf{rescattering} corrections (not covered in this talk)
    \end{itemize}
  \end{block}
  \begin{exampleblock}{}{}
    Wide range of applications of the advanced amplitudes in LHCb.
    Just two examples:
    \begin{itemize}
      \item Search for CP violation in baryonic decays
      \item Lineshape analysis for $\Lb$ spectroscopy
    \end{itemize}
  \end{exampleblock}
\end{frame}


