\subsection{General polarimetry}
\begin{frame}{Weak decay of a fermion deflects reflects polarization}
  \begin{minipage}{0.5\textwidth}
    {\large Example: $\Lambdares \to \proton \pim$}
    \begin{flalign*}
      H_{\lambda_{\Lambdares}, \lambda_{\proton}} = \left\langle \proton, \lambda_{\proton}; \pim| T_\mathrm{weak} |\Lambdares, \lambda_{\Lambdares} \right\rangle
      % : \text{ hadron property}
    \end{flalign*}
    \vspace*{-2em}
    \begin{flalign*}
      \frac{2}{\Gamma}\frac{\diff \Gamma}{\diff\cos\theta} = 1 + P \colred{\alpha} \cos\theta\,,\quad A_{FB} = \alpha P
      % : \text{ asymmetry}
    \end{flalign*}
  \end{minipage}
  \begin{tikzpicture}[overlay, remember picture]
    \node[blend mode=multiply] at (3.2, 0.1) {\includesvg[width=0.5\textwidth]{figures/Ldecay.svg}};
  \end{tikzpicture}
  \vspace*{0.7em}
  \begin{itemize}
    \item $P = |\vec{P}|$ polarization, for $J=1/2$, there are just tree d.o.f.
    \item \colred{$\alpha$} is the \textbf{asymmetry parameter}: \only<2>{\colred{If we know $\alpha$, we can measure $P$}}
  \end{itemize}
  \begin{block}{\centering Appears only when both PV and PC}
    \centering
    \vspace*{0.4em}
    {\large
    $\alpha = \frac{|H_{+}|^2-|H_{-}|^2}{|H_{+}|^2 + |H_{-}|^2} = -\frac{2\mathrm{Re}(H_{\color{cola}S}^* H_{\color{colb}P})}{|H_{\color{cola}S}|^2 + |H_{\color{colb}P}|^2}$ \\[0.7em]
    }
    ${\color{cola}S}$-wave -- parity violating (PV); ${\color{colb}P}$-wave -- parity conserving (PC): \\[0.2em]
    $\Lambdares\,(j^P = 1/2^\colred{+}) \, \to \, \proton\,(j^P = 1/2^\colred{+}) \; \pim(j^P = 0^\colred{-})$
  \end{block}
