\section*{Averaged polarimetry}

\begin{frame}[noframenumbering]{Optional simplification: averaging over dynamic variables}
  Can the dynamic variables $\tau$ be integrated over, i.e disregarded in the analysis?
  {\large
  \begin{align*}
    \frac{8\pi}{\Gamma}\frac{\diff^3 \Gamma}{\diff\phi\,\diff\cos\theta\,\diff\chi} = 1+\sum_{i,j=1}^3 P_i R_{ij}(\phi, \theta, \chi) \overline{\alpha}_j\,,
  \end{align*}
  }
  where $\vec{\overline{\alpha}}$ is \textbf{averaged aligned polarimeter vector}.\\[1em]
  \begin{alertblock}{Advantage / Disadvantage}
    \setlength{\leftmargini}{1.5em}
    \begin{itemize}
      \item[\color{Green}$+$] Only need know three numbers in order to determine polarization.
      \item[\color{Red}$-$] Uncertainty on $\vec{P}$ with averaged $\vec{\overline{\alpha}}$ is worse than with the full $\vec\alpha(\tau)$ field. \cite{Davier:1992nw}
    \end{itemize}
  \end{alertblock}
\end{frame}

