\begin{columns}
\begin{column}{0.6\paperwidth}
\textcolor[rgb]{0.0,0.5,0.0}{Introduce normalized invariants}
{\small
$$\begin{array}{l l l}
y_0 & = & (s_0-m_1^2-m_2^2)/(2m_1 m_2), \\
y_1 & = & (s_1-m_1^2-m_3^2)/(2m_1 m_3), \\
y_2 & = & (s_2-m_2^2-m_3^2)/(2m_2 m_3)
\end{array}$$
}
\end{column}
