\frame{ \frametitle{$K^\star \to K \pi$ $P$-wave decay}
%Simplest one is $K^\star K \pi$ decay.
\begin{itemize}
\item $P$-wave. In my parametrization:
$$
\Gamma = \frac{1}{2m_{K^\star}}\frac{1}{8\pi} \frac{2|\vec k|}{m_{K^\star}} \times 
g_{K^\star K\pi}^2 \frac{4}{3} |\vec k^2|.
$$
\item $\Gamma_{K^\star\to K\pi} = 50.8\,$MeV. So, $g_{K^\star K\pi}^2 = 31.2$.
\item From isospin $\text{Br}( K^{\star-} \to K^0 \pi^-) / \text{Br}(K^{*-} \to K^-\pi^0) = 2$.
\end{itemize}%\\[2cm]
%{\it \small
%(?) Barrier factor (Blatt-Weiskopf) vs meson size correction $F_R = e^{-1/2k^2 R^2}$.}
%

}

\frame{ \frametitle{$a_1$ decays}
The best knowledges are from $\tau$ decay (mass dependent analysis)
{\small
Short results: $\Gamma_{a_1}(m_{a_1}) = 800\,$GeV, \\
Br($a_1\to\rho \pi) \approx 60\%$, Br($a_1\to\sigma\pi) \approx 20\%$, Br($a_1\to f_0(1370)\pi) \approx 7\%$, Br($a_1\to K^\star \bar{K}) \approx 2.2\%$. \\
{\tiny \it Correction for 'finite size of meson' is done by exponential suppression (not by Blatt-Weitskopf), $R=1..2/$GeV$^2$ is strongly correlated with $\Gamma_{a_1}(m_{a_1})$.}
}
\begin{columns}
\begin{column}{0.47\paperwidth}
\begin{itemize}
\item $a_1\to \rho \pi$ $S$ wave 
\item $a_1\to \sigma \pi$ $P$ wave + BW
\item $a_1\to K^\star \bar{K}$ $S$ wave
\end{itemize}
Evaluation for $g_{a_1 K^\star K}^2 \approx 3.5\,$GeV$^2$, but can change with $\Gamma_{a_1}(m_{a_1})$.

