      \end{columns}
%       % \scalebox{0.6}{\parbox{\textwidth}{$$
%       % I = \sum_\text{pol.} |A_{\lambda_0,\lambda_1,\lambda_2}|^2
%       % $$}}
      \vspace{-2mm}
      \scalebox{0.8}{\parbox{\textwidth}{$$ 
      A_{\lambda_0,\lambda_1,\lambda_2} = 
        \underbrace{\raisebox{-0.5\height}{\includegraphics[width=0.27\textwidth]{general_isobar_12.pdf}}}_{A^{(12)}_{\lambda_0,\lambda_1,\lambda_2}} + 
        \underbrace{\raisebox{-0.5\height}{\includegraphics[width=0.27\textwidth]{general_isobar_23.pdf}}}_{A^{(23)}_{\lambda_0,\lambda_1,\lambda_2}} +
        \underbrace{\raisebox{-0.5\height}{\includegraphics[width=0.27\textwidth]{general_isobar_31.pdf}}}_{A^{(31)}_{\lambda_0,\lambda_1,\lambda_2}}
      $$}}
    \end{column}
    \begin{column}{0.37\textwidth}
      \vspace{-6mm}
      \begin{overpic}[width=\textwidth]{Dalitz_plot_pc.pdf}
        % \put(60,30) {\includegraphics[width=0.25\textwidth]{Penta_isobar_12.pdf}}
        % \put(30,60) {\includegraphics[width=0.25\textwidth]{Penta_isobar_23.pdf}}
      \end{overpic}
    \end{column}
  \end{columns}

  \vspace{-5mm}
  \begin{columns}
    \begin{column}{0.5\textwidth}
      \begin{exampleblock}{}
        \textbf{Used in the past}
        \centering
        \scalebox{0.6}{\parbox{\textwidth}{$$
        A_{\lambda_0,\lambda_1,\lambda_2}^{(23)} = 
          \underbrace{\blackhatchedsquare(\phi_i,\theta_i)}_{0\to X,1} \times
          \underbrace{\blackhatchedsquare(\phi_i',\theta_i')}_{X\to 2,3} \times
          \underbrace{\bluehatchedsquare(\phi_i'',\theta_i'')}_{\text{spin align.}}
        $$}}
        \small
        \vspace{-2mm}
        \begin{itemize}
          \item "impossible" to get right
          \item spin $1/2$: $A(\pi) \neq A(-\pi)$
          \item range of $\phi$ matters $[-\pi,\pi]$ vs $[0,2\pi]$
        \end{itemize}
        \end{exampleblock}      
    \end{column}
    \begin{column}{0.44\textwidth}
