    \end{itemize}
  \end{alertblock}
\end{frame}

\begin{frame}{Triangle Singularity (TS) as a nature of the $X(1420)$ \paper{MM et al., PRD 91 (2015)}}
  {A three-body rescattering effect due to the coupling $3\pi / K\bar{K}\pi$}

  \begin{columns}
    \begin{column}{0.33\textwidth}
      \centering
      \includegraphics[width=0.9\textwidth]{a1-decay-2.pdf}
      \small
      \begin{itemize}
        \item The rescattering $K^\star K\to f_0 \pi$ kinematically allowed with
          a real $K$-exchange.
        \item[$\Rightarrow$] Landau singularity (TS)
      \end{itemize}
    \end{column}
    \begin{column}{0.65\textwidth}
      \small
      \begin{itemize}
        \item Inelasticity $\pi\pi\leftrightarrow K\bar{K}$ causes redistribution of events between final states $3\pi$, $K\bar{K}\pi$.
      \end{itemize}
      \begin{overpic}[width=0.45\textwidth]{intensity_combined.pdf}
      \end{overpic}\,\,
      \begin{overpic}[width=0.45\textwidth]{argand_combined.pdf}
        \put(20,13) {\paper{CERN-EP-2020-104 (in review in PRL)}}
      \end{overpic}
      \vspace{-2mm}
      \begin{block}{}
        \small
        \begin{itemize}
          \item TS model has the same quality as the BW (dashed)
          \item No mass/width parameters: the shape is fixed
          \item The size of the effect matches the expectations
        \end{itemize}  
      \end{block}
    \end{column}
  \end{columns}
  \begin{alertblock}{}
    \small
    A theoretical idea has turned into to the first rigid observation of the Triangle Singularity
  \end{alertblock}
\end{frame}

