\begin{frame}{Infinite Resistor Ladder Puzzle\hfill\paper{arXiv:2105.03690}}
  \begin{columns}
    \begin{column}{0.45\textwidth}
      Equivalent resistance of the infinite ladder of the chains:
      \begin{itemize}
        \item<2-> Solved by adding one more unit cell
        $$
        R_{\alpha\beta} = 1+\frac{R_{\alpha\beta}}{1+R_{\alpha\beta}}
        $$
        \item<2-> The answer is the golden ratio
      \end{itemize}
    \end{column}
    \begin{column}{0.5\textwidth}
