\subsection{Polarimetry}
\begin{frame}{Measuring polarization -- two-body decays}{Decay of a fermion is special -- baryon in the final state averages angular distributions}
	\begin{minipage}{0.5\textwidth}
		{\large Example: $\Lambdares \to \proton \pim$}
		\begin{flalign*}
			H_{\lambda_{\Lambdares}, \lambda_{\proton}} = \left\langle \proton, \lambda_{\proton}; \pim| T_\mathrm{weak} |\Lambdares, \lambda_{\Lambdares} \right\rangle
			% : \text{ hadron property}
		\end{flalign*}
		\vspace*{-2em}
		\begin{flalign*}
			\frac{2}{\Gamma}\frac{\diff \Gamma}{\diff\cos\theta} = 1 + P \alpha \cos\theta\,,\quad A_{FB} = \alpha P
			% : \text{ asymmetry}
		\end{flalign*}
	\end{minipage}
	\begin{tikzpicture}[overlay, remember picture]
		\node[blend mode=multiply] at (3.2, 0.1) {\includesvg[width=0.5\textwidth]{Ldecay.svg}};
	\end{tikzpicture}
	\vspace*{0.7em}
	\begin{itemize}
		\item $P = |\vec{P}|$ polarization, for $J=1/2$, there are just tree d.o.f.
		\item $\alpha$ is the \textbf{asymmetry parameter} (analyzing power of the decay)
	\end{itemize}
	\begin{minipage}{0.75\textwidth}
		\begin{alertblock}{\centering Appears only when both PV and PC}
			\centering
			\vspace*{0.4em}
			{\large
			$\alpha = \frac{|H_{+}|^2-|H_{-}|^2}{|H_{+}|^2 + |H_{-}|^2} = -\frac{2\mathrm{Re}(H_{\color{cola}S}^* H_{\color{colb}P})}{|H_{\color{cola}S}|^2 + |H_{\color{colb}P}|^2}$ \\[0.7em]
			}
			${\color{cola}S}$-wave -- parity violating (PV); ${\color{colb}P}$-wave -- parity conserving (PC): \\[0.2em]
			$\Lambdares\,(j^P = 1/2^\colred{+}) \, \to \, \proton\,(j^P = 1/2^\colred{+}) \; \pim(j^P = 0^\colred{-})$
		\end{alertblock}
	\end{minipage}
	\only<2>{%
		\begin{tikzpicture}[overlay]
			\draw[line width=0.5pt, draw=BrickRed] (-9.9, 2.9) rectangle ++(3.9, 0.95);
			\draw[-stealth, draw=BrickRed] (0.9, 1.3) -- (-0.2, 2.8) -- (-5.9, 3.0);
			\node[align=left, draw=BrickRed, fill=white, text=BrickRed] at (0.75, 0.8) {%
				If we know $\alpha$, we can measure $P$. \\[0.5em]
				But what about \textbf{multibody} decays?%
			};
		\end{tikzpicture}
	}
\end{frame}

