\begin{frame}{Measuring polarization -- polarimetry in $\Ptau$ decays}
	{\scriptsize\realcite{Tsai:1971vv, Kuhn:1991cc, Davier:1992nw, Kuhn:1995nn, Kuhn:1982di, Kuhn:1993ra, Hagiwara:1989fn}}
	Idea: similar relation for $\Ptau$ lepton decays,
	\begin{align*}
		\frac{\Phi}{\Gamma}\,\frac{\diff \Gamma}{\mathrm{d}\Phi} \propto 1+ \vec{P}\cdot\vec{h}\,.
	\end{align*}
	\begin{itemize}
		\item $\vec{P}$ is a polarization of $\Ptau$
		\item $\vec{h}$ is a \textbf{polarimeter vector}
	\end{itemize}
	\begin{block}{Polarimeter vector of the $\Ptau$ lepton in the SM}
		\begin{itemize}
			\item Direction depends on the final state, e.g.
			      \begin{itemize}
				      \item for \mbox{$\Ptau^- \to {\color{BrickRed}\pim} \neut$} decay, $\vec{h} \uparrow\uparrow \vec{p}_{\color{BrickRed}\pim}$
				      \item for $\Ptau^-\to \lepton \neut {\color{BrickRed}\neulb}$ decay, $\vec{h} \uparrow\uparrow \vec{p}_{\color{BrickRed}\neulb}$
			      \end{itemize}
			\item Unit vector: $|\vec{h}| = 1$.
		\end{itemize}
	\end{block}
\end{frame}

\begin{frame}{Measuring polarization -- general multibody decays?}{$\rightarrow$ Dalitz-Plot Decomposition (DPD)}
	Factorization of variables describing dynamics and polarization~\cite{JPAC:2019ufm}:
	{%
	\Large
	\begin{equation*}
		T_{\nu_0,\{\lambda\}}(\phi,\theta,\chi; \tau) = \sum_{\nu}
		{\color{cola} D_{\nu_0,\nu}^{1/2}(\phi,\theta,\chi)}
		\,
		{\color{colb} A_{\nu,\{\lambda\}}(\tau)}
	\end{equation*}%
	}
	\vspace*{-1em}
	\begin{columns}[T]
		\begin{column}{0.5\textwidth}
			{\centering\color{cola}\textbf{Polarization d.o.f.}}
			\begin{itemize}
				\item Euler angles in active ZYZ convention
				\item rotation of the system as rigid body
				\item polarization affects angular distribution
			\end{itemize}
			~\\
			{\centering\color{colb}\textbf{Dynamic d.o.f.}}
			\begin{itemize}
				\item Mandelstam variables of the subsystems
				\item describes resonances in the decay
			\end{itemize}
		\end{column}
		\begin{column}{0.5\textwidth}
		\end{column}
	\end{columns}
	\begin{tikzpicture}[overlay, remember picture]
		\node[blend mode=multiply] at (9.8, 1.6) {%
			\includesvg[width=0.6\textwidth]{angle-definitions-red.svg}%
		};
	\end{tikzpicture}
\end{frame}

