\begin{frame}[t]{A new technique: symbolic amplitude models}
	\begin{tikzpicture}[overlay, remember picture]
		\node[blend mode=multiply] at (8.8, -2.8) {%
			\includegraphics[height=0.9\textheight]{CAS-conversion-large.pdf}%
