\section{Theory}

\subsection{Importance of polarization}
\begin{frame}{What can we learn by measuring polarization of hadrons?}
	\textit{Polarization = preferred orientation of the spin of a particle in space}
	\begin{itemize}
		\item Mechanism of quark hadronization~\cite{Brambilla:2010cs, Faccioli:2010kd, Butenschoen:2012px}
		\item BSM searches with $\Lb \to \Lc \lepton^- \Pnu$ \cite{Konig:1993wz, Dutta:2015ueb, Shivashankara:2015cta, Li:2016pdv, Li:2016pdv, Datta:2017aue, Ray:2018hrx, DiSalvo:2018ngq, Penalva:2019rgt, Ferrillo:2019owd} \\
		      {\footnotesize E.g. sign of longitudinal polarization of $\Lc$ provides a test for left-handedness of $\bquark \to \cquark$~current}
		\item BSM searches with measurement of EDM/MDM with charmed mesons
			      {\color{blue}\scriptsize [Baryshevsky:2016cul, Botella:2016ksl, Fomin:2017ltw]}
		\item Hadron spectroscopy, extending decay chains (next slide)
		      \begin{itemize}
			      \item[\color{Green}~$\checkmark$] $\Lb \to \jpsi \proton \kaon$ with {\color{Green}$\jpsi \to \mup\mun$}
			      \item[\color{Green}~$\checkmark$] $\baryon \to \jpsi \antiproton \Lambdares$ with {\color{Green}$\Lambdares \to \proton \pim$}
			      \item[\color{Orange}$?$~] $\baryon^+ \to \Lc \Lcbar \Kp$ with {\color{Orange}$\Lc \to \proton \Km \pip$}
			      \item[\color{Orange}$?$~] $\Omegab \to \Xicp \pim \Km$ with {\color{Orange}$\Xicp \to \proton \Km \pip$}
		      \end{itemize}
	\end{itemize}
\end{frame}

