\begin{frame}<presentation:0>{Polarization sensitivity by Davier et al.}
	Determination of polarization is a linear problem
	$$
		\unpolrate(\xi|P) = f(\xi) + P g(\xi)\,,\quad
		\text{where }\xi\text{ are kinematic variables.}
	$$
	For the likelihood fit of the set $\{\xi_i\}_N$,
	the error to $P$ can be computed analytically:
	$$
		P = P_\text{mod} \pm \delta_P, \quad \delta_P = \frac{1}{S_P\sqrt{N}},
		\text{ where }
		S_P^2 = \int \frac{g^2}{f+P g} d^n \xi
	$$
	\begin{alertblock}{Using the relations with our master formula}
		$$
			S_0 = 3 \int \unpolrate \left|\vec{\alpha}\right|^2 \diff^n \tau \,\big /\, \int \unpolrate\,\diff^n \tau
		$$
		\begin{itemize}
			\item For integrated setup,
			      $\overline{S}_0^2 = 3(\overline{\alpha}_x^2+\overline{\alpha}_y^2+\overline{\alpha}_z^2)$
			\item The ratio $S_0 / \overline{S}_0$ gives the expected increase of the statistical uncertainty
		\end{itemize}
	\end{alertblock}
\end{frame}

