\begin{frame}{Another application: extending amplitude models}
	{A Example: $B^+ \to \Lc \Lcbar \Kp, \quad {\color{BrickRed}\Lz_{\cquark} \to \proton \kaon \pion}$}
	\begin{minipage}{0.7\textwidth}
		Normally, without polarization taken into account:
		\begin{align*}
			 & I\left(m_{\Lc K^+}^2, m_{\Lcbar K^+}^2\right) = \sum_{\nu_0,\bar{\nu}_0}
			\left| O_{\nu_0,\bar{\nu}_0}^{B}(m_{\Lc K^+}^2, m_{\Lcbar K^+}^2) \right|^2
		\end{align*}
		\begin{tikzpicture}[overlay]
			\node at (11.4, 1.4) {%
				\begin{minipage}{.46\textwidth}
					\begin{block}{Physics motivation}
						\setlength{\leftmargini}{1.2em}
						\begin{itemize}
							\item exotic structures in $\Lc \Lcbar$
							\item studies of $\Xic^{**}$ in $\Lc \kaon$
						\end{itemize}
						{\footnotesize\realcite{BaBar:2007xtc, Belle:2017jrt, Belle:2018yob, LHCb:2022vns}}
					\end{block}
				\end{minipage}
			};
		\end{tikzpicture}
		\pause
		Polarimeter provides \textbf{10 additional degrees of freedom}:
		\begin{align*}
			 & I\left(m_{\Lc \Kp}^2, m_{\Lcbar \Kp}^2;
			{\color{colc} \phi},
			{\color{colc} \theta},
			{\color{colc} \chi},
			{\color{colc} m_{\proton\Km}^2},
			{\color{colc} m_{\Km\pip}^2};
			{\color{colc} \bar{\phi}},
			{\color{colc} \bar{\theta}},
			{\color{colc} \bar{\chi}},
			{\color{colc} m_{\antiproton\Kp}^2},
			{\color{colc} m_{\Kp\pim}^2}
			\right) =                                                                                                                                                            \\
			 & \quad\sum_{\nu_0,\bar{\nu}_0,\nu,\bar{\nu}}
			\sum_{\nu_0',\bar{\nu}_0',\nu',\bar{\nu}'}
			O_{\nu_0',\bar{\nu}_0'}^{B*}(m_{\Lc \Kp}^2, m_{\Lcbar \Kp}^2)
			O_{\nu_0,\bar{\nu}_0}^B(m_{\Lc \Kp}^2, m_{\Lcbar \Kp}^2)                                                                                                             \\
			 & \qquad \times D^{1/2*}_{\nu_0',\nu'}(\phi,\theta,\chi) D^{1/2}_{\nu_0,\nu}(\phi,\theta,\chi) {\color{BrickRed} X_{\nu',\nu}^\Lc (m_{\proton\Km}^2,m_{\Km\pip}^2)} \\
			 & \qquad \times D^{1/2*}_{\bar{\nu}_0',\bar{\nu}'}(\bar{\phi},\bar{\theta},\bar{\chi}) D^{1/2}_{\bar{\nu}_0,\bar{\nu}}(\bar{\phi},\bar{\theta},\bar{\chi})\,
			{\color{BrickRed} X_{\bar{\nu}',\bar{\nu}}^\Lcbar(m_{\antiproton\Kp}^2,m_{\Kp\pim}^2)}
		\end{align*}
	\end{minipage}
	\begin{tikzpicture}[overlay]
		\node[align=left, draw=BrickRed, fill=white, text=BrickRed] at (0.7, -2.2) {%
			\large $X_{\nu',\nu}(\tau) \; =$  \\
			\large $\quad \frac{I_0(\tau)}{2} \left(1+\vec\alpha(\tau) \cdot \vec\sigma^{P}\right)_{\nu',\nu}$
		};
		\node[text=BrickRed] at (0.5, -3.15) {\bfseries No need to fit these d.o.f.};
	\end{tikzpicture}
\end{frame}

\section{\CP properties of the polarimetry field}
\begin{frame}{Appendix: conjugation of the $\alpha$ under \CP}
	{Observable for \CP-violation}
	\begin{exampleblock}{How to check \CP properties:}
		\begin{columns}
			\begin{column}{0.5\textwidth}
				\begin{itemize}
					\item Assume that \CP is conserved
					\item Find the transition amplitude for $\Lcbar$:
					      \begin{itemize}
						      \item apply $C$: \Lc \to \Lcbar,
						      \item apply $P$: $\vec{p}\to -\vec{p}$, $\lambda\to-\lambda$
					      \end{itemize}
				\end{itemize}
			\end{column}
			\begin{column}{0.52\textwidth}
				\vspace{1cm}
				\begin{align*}
					T_{\nu_0,\lambda}^{\Lcbar}(\vec{p}_1, \vec{p}_2, \vec{p}_3) =
					T_{\nu_0,-\lambda}^{\Lc}(-\vec{p}_1, -\vec{p}_2, -\vec{p}_3)
				\end{align*}
			\end{column}
		\end{columns}
	\end{exampleblock}
	The polarimeter vector is computed the amplitude $T$:
	\begin{align*}
		\alpha_x^{\Lcbar} & = -\alpha_z^{\Lc}\,, &
		\alpha_y^{\Lcbar} & =  \alpha_y^{\Lc}\,, &
		\alpha_z^{\Lcbar} & = -\alpha_z^{\Lc}\,.
	\end{align*}
	Equivalently, \fbox{$\vec\alpha^{\Lcbar} =  R_y(\pi) \vec\alpha^{\Lc}$}\,.
	\vspace{-1mm}
	\begin{block}{Note on two-body decays}
		\centering
		Only $z$ component is non-zero: $\vec{\alpha}_\text{2b} = (0,0,\alpha)$.
		Hence, $A_\CP^{\alpha,\text{2b}} = \frac{\alpha+\bar{\alpha}}{\alpha-\bar{\alpha}}$\,.\\
		The best measured value, $A_\CP^{\alpha,\varLambda\to p\pim} = -0.002 \pm 0.012$
	\end{block}
\end{frame}

\section{SU(2) \texorpdfstring{$\to$}{→} SO(3) homomorphism}
\label{subsec:homomorphism}
\begin{frame}{\secname}{Finding a general expression for $\vec\alpha(\tau)$}
	The \textbf{polarized decay rate} is given by:
	{%
	\large
	\begin{equation*}
		\left|\mathcal{M}\right|^2 = \sum_{\nu_0,\nu_0',\{\lambda\}}\mathfrak{R}_{\nu_0',\nu_0} T_{\nu_0',\{\lambda\}}^* T_{\nu_0,\{\lambda\}},
		\qquad
		\mathfrak{R}_{\nu_0',\nu_0} = \frac{1}{2}\left(1+\vec{P} \cdot \vec\sigma^P\right)_{\nu_0',\nu_0}
	\end{equation*}
	}
	\begin{block}{Trick for factoring out polarization \cite{Cornwell:1997ke}}
		\textbf{SU(2) is double cover of SO(3)} \hfill spin $1/2$, $4\pi$ rotation\\
		Explicit homomorphism with the non-trivial centre:
		$$
			\phi: \text{SU(2)} \to \text{SO(3)},\qquad \phi(d) = R\,,
		$$
		$$
			\phi(d) = \frac{1}{2}\text{Tr}\left[
				D^{1/2*}(\phi,\theta,\chi) \sigma^P_i D^{1/2}(\phi,\theta,\chi) \sigma^P_j
				\right] = R_{ij}(\phi,\theta,\chi),
		$$
	\end{block}
	\begin{tikzpicture}[overlay]
		\node[draw=BrickRed, fill=white] at (11.2, 4.3) {%
			\small
			$
				T_{\nu_0,\{\lambda\}} = \sum\limits_{\nu}
				D_{\nu_0,\nu}^{1/2}(\phi,\theta,\chi)\,
				A_{\nu,\{\lambda\}}
			$
		};
	\end{tikzpicture}
\end{frame}

