\begin{exampleblock}{Setup: $X\to VV$}
  \begin{itemize}
    \item $X$ is a particle produced in strong interaction prompt $pp$ collision
    \item $V$ is a vector particle, consider $J/\psi$, $\phi$, $Z^0$, $\gamma$
    \item $VV$ are identical
  \end{itemize}
\end{exampleblock}
