\begin{frame}{$X\to VV$ amplitude}{}
\begin{columns}
  \begin{column}{0.48\textwidth}
    % {\Large
    Amplitude:
    \begin{equation*}
      A_{\lambda_1,\lambda_2}^{M} = n_J\,d_{M,\lambda_1-\lambda_2}^{{\color{red} J}}(\theta) H_{\lambda_1,\lambda_2} (-1)^{1-\lambda_2}
    \end{equation*}%}
    Differential width (intensity):
    \begin{equation*}
      I(\theta) = \sum_M \rho_M \sum_{\lambda_1,\lambda_2} |A_{\lambda_1,\lambda_2}^{M}|.
    \end{equation*}
  \end{column}
  \begin{column}{0.5\textwidth}
    \includegraphics[width=\textwidth]{figs/production.pdf}
  \end{column}
\end{columns}
\begin{block}{Production by $pp$ collision}
  \begin{itemize}
    \item parity conservation $\Rightarrow$ no longitudinal polarisation
    \item moreover, can only be polarized perpendicular to the production plane $\vec{n}$
    \item choose $z \uparrow\uparrow \vec{n}$ $\Rightarrow$ diagonal polarization matrix $\delta_{M,M'}\rho_M$
  \end{itemize}
\end{block}
\end{frame}

\begin{frame}{Intensity for the unpolarized decay}
\begin{align*}
    I(\theta) = n_J^2 \sum_{M,\lambda_1,\lambda_2} \rho_M |d_{M,\lambda_1-\lambda_2}^{{\color{red} J}}(\theta)|^2 |H_{\lambda_1,\lambda_2}|^2
\end{align*}
What is no polarization $\rho_M = 1$ (quite likely in $pp$)?
\begin{align*}
    I(\theta) = n_J^2 \sum_{\lambda_1,\lambda_2} |H_{\lambda_1,\lambda_2}|^2
\end{align*}
\begin{block}{no ${\color{red} J}$: explicit dependence on $J$ disappears. What helps to determine $J$?}
  \begin{itemize}
    \item[(a)] Can helicity couplings tell us something?
    \item[(b)] Will the decays of $V$ help?
  \end{itemize}
\end{block}
% no ${\color{red} J}$, since
% \begin{equation*}
%   \sum_M |d_{M,\lambda_1-\lambda_2}^{{\color{red} J}}(\theta)|^2 = 1
% \end{equation*}
% Ops...
\end{frame}

\section{Adding vector decays}

\begin{frame}{Four-body decay angles}
  \begin{center}
    \includegraphics[width=0.9\textwidth]{figs/angles.pdf}
  \end{center}
  \begin{itemize}
    \item $\theta$ is the polar angle of $(J/\psi)_1$ with respect to the polarization direction
    \item $(\theta_1,\phi_1)$ are the spherical angles of $\mu^+$ in the $(J/\psi)_1$ helicity frame
    \item $(\theta_2,\phi_2)$ are the spherical angles of $\mu^+$ in the $(J/\psi)_2$ helicity frame
  \end{itemize}
  \begin{exampleblock}{}
    No polarization $\Rightarrow$ no $z$ $\Rightarrow$ no decay plane (pink) $\Rightarrow$ only $\phi=\phi_1+\phi_2$ matters.% Three angles
  \end{exampleblock}
\end{frame}

\begin{frame}{$X\to V(\mu,\mu)V(\mu,\mu)$ amplitude}{}
  {\Large
  \begin{align*}
    A_{\xi_1,\xi_2}^{M} &= n_J\,\sum_{\lambda_1,\lambda_2}d_{M,\lambda_1-\lambda_2}^{{\color{red} J}}(\theta) H_{\lambda_1,\lambda_2} (-1)^{1-\lambda_2}\\
    &\qquad \times n_1 D_{\lambda_1,\xi_1}^{1*}(\phi_1,\theta_1,0)\\
    &\qquad \times n_1 D_{\lambda_2,\xi_2}^{1*}(\phi_2,\theta_2,0)
  \end{align*}}
  \begin{itemize}
    \item $\xi_i = \lambda_{\mu^+,i}-\lambda_{\mu^-,i}$ difference of muon helicities
    \item $\xi \in \{-1,1\}$ since $\xi=0$ is suppressed by $m_\mu/m_{J/\psi}$.
  \end{itemize}
  {\small\color{gray}
  \begin{align*}
    F^{(\mu\mu)} = \sum_{\xi\in\{-1,1\}}\int \diff \cos\theta d_{\lambda,\xi}^{1}(\theta) d_{\lambda',\xi}^{1}(\theta) =
    \frac{1}{3}\begin{pmatrix}
       2 & 0 & 1\\
       0 & 2 & 0\\
       1 & 0 & 2
    \end{pmatrix}_{\lambda,\lambda'}
  \end{align*}}
\end{frame}

\begin{frame}[noframenumbering]{$X\to V(K^+,K^-)V(K^+,K^-)$ amplitude}{}
  {\Large
  \begin{align*}
    A_{}^{M} &= n_J\,\sum_{\lambda_1,\lambda_2}d_{M,\lambda_1-\lambda_2}^{{\color{red} J}}(\theta) H_{\lambda_1,\lambda_2} (-1)^{1-\lambda_2}\\
    &\qquad \times n_1 D_{\lambda_2,0}^{1*}(\phi_1,\theta_1,0)\\
    &\qquad \times n_1 D_{\lambda_2,0}^{1*}(\phi_2,\theta_2,0)
  \end{align*}}
  \begin{itemize}
    \item $\phi\to K^+K^-$ $P$-wave
  \end{itemize}
  \begin{block}{}
    The difference in marginal: no final state spin.
  \end{block}
  {\small\color{gray}
  \begin{align*}
    F^{(KK)} = \int \diff \cos\theta d_{\lambda,0}^{1}(\theta) d_{\lambda',0}^{1}(\theta) =
    \frac{1}{3}\begin{pmatrix}
       1 & 0 & -1\\
       0 & 1 &  0\\
      -1 & 0 &  1
    \end{pmatrix}_{\lambda,\lambda'}
  \end{align*}}
\end{frame}

\section{Symmetry constraints}
\begin{frame}{Helicity couplings\hfill\paper{Martin, Spearman (1970) book}}{Reappearance of {\color{red} $J$}}
  \begin{align*}
    \ket{\text{two part. state}; \lambda_1,\lambda_2} &= \ket{\vec{p},\lambda_1}\otimes\ket{-\vec{p},\lambda_2} {\color{gray}(-1)^{j_2-\lambda_2}}\\
    \ket{JM;\lambda_1,\lambda_2} &= n_J\int\frac{\diff \Omega}{4\pi} D_{M\lambda}^{J*} \ket{\text{two part. state}; \lambda_1,\lambda_2}\\
  \end{align*}
  \begin{equation*}
    \fbox{$H_{\lambda_1,\lambda_2} = \bra{{\color{red}J}M;\lambda_1,\lambda_2}\hat{T}\ket{{\color{red}J}M}$}
  \end{equation*}
  \begin{block}{}
    \vspace{-5mm}
    \begin{align*}
      &\mathrm{Parity}&
      \mathcal{P}\,\ket{JM;\lambda_1,\lambda_2} &= (-1)^{J} \eta_V^2
      \ket{JM;-\lambda_1,-\lambda_2}.
    \end{align*}
  \end{block}
  \vspace{-1mm}
  \begin{exampleblock}{}
    \vspace{-5mm}
    \begin{align*}
      &\mathrm{Permutation}\,\,1 \leftrightarrow 2 &
      \mathcal{P}_{12}\,\ket{JM;\lambda_1,\lambda_2} &= (-1)^{J}
      \ket{JM;\lambda_2,\lambda_1}.
    \end{align*}
  \end{exampleblock}
  \vspace{-1mm}
  \begin{alertblock}{}
    \vspace{-5mm}
    \begin{align*}
      \Rightarrow &&
      H_{\lambda_1,\lambda_2} &= (-1)^{J} \,\eta_{X} \,H_{-\lambda_1,-\lambda_2}, &
      H_{\lambda_1,\lambda_2} &= (-1)^{J} H_{\lambda_2,\lambda_1}.
    \end{align*}
  \end{alertblock}
\end{frame}

\section{Matrix of helicity couplings}

\begin{frame}{Matrix of helicity couplings}
{\Huge
\begin{align*}
  \color{black}
  H_{\lambda_1,\lambda_2} =
  \begin{pmatrix}
    {\color{colc} h_{ 1,1}} & {\color{cola} h_{ 1, 0}} & {\color{colb} h_{ 1,-1}}\\
    {\color{cola} h_{ 0,1}} & {             h_{ 0, 0}} & {\color{cola} h_{ 0,-1}}\\
    {\color{colb} h_{-1,1}} & {\color{cola} h_{-1, 0}} & {\color{colc} h_{-1,-1}}
  \end{pmatrix}
\end{align*}
}
The same-color elements are connected by symmetries.
\begin{exampleblock}{The symmetry relates the couplings}
  \vspace{-5mm}
  \begin{align*}
    H_{\lambda_1,\lambda_2} &= (-1)^{J} \,\eta_{X} \,H_{-\lambda_1,-\lambda_2}, &
    H_{\lambda_1,\lambda_2} &= (-1)^{J} H_{\lambda_2,\lambda_1}.
  \end{align*}
\end{exampleblock}
\end{frame}

