\begin{frame}{Landau-Yang theorem}
  \begin{center}
    \fbox{"A massive particle with spin 1 cannot decay into two photons", wikipedia}
  \end{center}
\begin{block}{}
  Photons do not carry the longitudinal polarizarion $\Rightarrow$ $H_{0,i}=H_{i,0} = 0$
\end{block}
  \begin{align*}
    & \qquad H^{(\I)}&
    & \qquad H^{(\II)}&
    & \qquad H^{(\III)}&
    & \qquad H^{(\IV)}&\\
    &\begin{pmatrix}
      b & a & c\\
      a & d\verline & a\\\overtabline
      c & a & b
    \end{pmatrix}_S&
    &\begin{pmatrix}
      b & a &  \\
      a & {\color{white}0}\verline & -a\\\overtabline
        & -a & -b
    \end{pmatrix}_S&
    &\begin{pmatrix}
        & a &  \\
      -a & {\color{white}0}\verline & -a\\\overtabline
        & a &
    \end{pmatrix}_A&
    &\begin{pmatrix}
        & a & c\\
      -a & {\color{white}0}\verline & a\\\overtabline
      -c & -a &
    \end{pmatrix}_A\\
    &\begin{pmatrix}
      b & {\color{white}a} & {\color{white}c}\\
      {\color{white}a} & d\verline & {\color{white}a}\\\overtabline
      {\color{white}c} & {\color{white}a} & b
    \end{pmatrix}_S&
    &\begin{pmatrix}
      b & {\color{white}a} &  \\
      {\color{white}a} & {\color{white}0}\verline & {\color{white}-a}\\\overtabline
        & {\color{white}-a} & -b
    \end{pmatrix}_S&
    &{\color{white} \begin{pmatrix}
        & {\color{white}a} &  \\
      {\color{white}-a} & \verline  & {\color{white}-a}\\
        & {\color{white}a} &
    \end{pmatrix}_A}&
    &\begin{pmatrix}
        & a & {\color{white}c}\\
      -a & {\color{white}0}\verline & a\\\overtabline
      {\color{white}-c} & -a &
    \end{pmatrix}_A\\
    & \qquad \fbox{$0^+$}&
    & \qquad \fbox{$0^-$}&
    & \qquad {\color{white} \fbox{$0^+$}}&
    & \qquad \fbox{$1^+$}&
  \end{align*}
  \vspace{-3mm}
  \begin{exampleblock}{}
    \centering
    No decay to two photons for $1^+$, and group-\III: $1^-$, $3^-$, $5^-$, \dots
  \end{exampleblock}
\end{frame}

\section{Hypothesis testing}
\begin{frame}{Determination of the spin-parity}{LLH comparison}
  \begin{itemize}
    \item Only group can be determined without polarization
    \item Already something(!) - to distinguish $0^{\pm}$, $1^{\pm}$, $2^{\pm}$.
  \end{itemize}
  \begin{exampleblock}{Likelihood of hypothesis (model $\M$):}
    \begin{equation*}
      \LLH_\M = -\sum_{e=1}^{N_\mathrm{ev}} \log I(\tau_e|\M\{\hat{h}\}), % \frac{1}{N_\mathrm{ev}}
    \end{equation*}
    \begin{align*}
      \mathrm{Test\,\,statistics:} && \TS_{\M,\M'} = \LLH_{\M} - \LLH_{\M'}
    \end{align*}
  \end{exampleblock}
  \begin{itemize}
    \item parameters of the model are unknown couplings $\M\{h\}$
    \item evaluation of the LLH for the optimized values $\M\{\hat{h}\}$
  \end{itemize}
\end{frame}

\section{Example: the SM Higgs decay}
\begin{frame}{Higgs decay to $ZZ$: $J^P =  0^+$}
  \begin{columns}
    \begin{column}{0.45\textwidth}
The term in the SM lagrangian:
  \begin{equation*}
    \mathcal{L}_{ZZH} = \frac{m_Z^2}{2v} Z_\mu Z^\mu H
  \end{equation*}
Helicity amplitude:
\begin{equation*}
  A^{H\to ZZ}_{\lambda_1,\lambda_2} = \frac{m_Z^2}{2v} (\epsilon_1^*(\lambda_1)\cdot\epsilon_2^*(\lambda_2)).
\end{equation*}
Matrix of couplings:
\begin{equation*}
  H_{\lambda_1,\lambda_2} \Rightarrow
  \frac{1}{\sqrt{3}}
  \begin{pmatrix}
    1 & 0 & 0\\
    0 & 1 & 0\\
    0 & 0 & 1
  \end{pmatrix}
\end{equation*}
First group: $b=d=1$.
\end{column}
