            \end{itemize}
        \end{itemize}
    \end{block}
    \begin{exampleblock}{$\Pcs$ in $\varXi_b^{-}$ decay}
        \begin{itemize}
            \item Significant (stat: $5\sigma$ (syst: $3\sigma$)) structure in $J/\psi \Lambda$ spectrum around $\sim 4.46\,$GeV
            \item $\Pcs(4459)$ with the width of $17.3 \pm 6.5^{+8.0}_{-5.7}\,$MeV % or a dublet, $\Pcs(4455)$ and $\Pcs(4468)$
            \item Quantum number in the nominal fit $J^P = 5/2^-$, while others are not excluded.
        \end{itemize}
    \end{exampleblock}
\end{frame}


