\begin{frame}{The Dalitz-Plot decomposition\hfill\paper{MM et al.(JPAC), PRD 101, 034033 (2020)}}{Reformulation of the helicity approach}
  \begin{align*}
        % M^{\Lambda}_{\{\lambda\}}
        % &=
        \raisebox{-0.5\height}{
        \includegraphics[width=0.4\textwidth]{inline-figs/general_decay_with_labels.pdf}} =
        \sum_\nu
        \underbrace{{D_{\Lambda\nu}^{J*}(\color{red}\phi_1,\theta_1,\phi_{23}})}_{\text{Decay-plane orientation}}\,\times\,
        \underbrace{O^{\nu}_{\{\lambda\}}({\color{red}\{\sigma\}})}_{\text{Dalitz-plot function}}
        % }
        \end{align*}
        Model-independent factorization of the overall rotation:
        \begin{itemize}
            \item Exploits properties of the Lorentz group (orientation -- just three Euler angles)
            \item Dalitz-plot function depends entirely on 2 variables, $\{\sigma\}\equiv\{\sigma_1,\sigma_2,\sigma_3\}$
            \item No azimuthal phase factors in $O^{\nu}_{\{\lambda\}}$.
        \end{itemize}
        \begin{exampleblock}{Gives significant benefits to}
            \begin{itemize}
                \item Pentaquark analysis, $\Lambda_b/\Lambda_c$ polarionation measurements, Baryonic decay chains,\dots
            \end{itemize}
            % {\scriptsize (see a talk of Liming Zhang on Thursday)}
        \end{exampleblock}
\end{frame}

