\begin{frame}{Dalitz-Plot function\hfill \paper{MM et al.(JPAC), PRD 101, 034033 (2020)}}
\begin{block}{Master formula $0\to 1\,2\,3$ decay with arbitrary spins}
      \vspace{-2mm}
      \begin{align*}
          O^{\nu}_{\{\lambda\}}({\color{red}\{\sigma\}})
          %
          &= \sum_{(ij)k}\sum_{s}^{(ij)\to i,j}\sum_\tau \sum_{\{\lambda'\}}
                    n_Jn_s\,
                    d^{J}_{\nu,\tau-\lambda_k'}({\color{colc}\hat{\theta}_{k(1)}})
                    % \HellH{0\to(ij),k}_{\tau,\lambda_k'}\,
                    % X_s(\sigma_k)\,
                    % d^{s}_{\tau,\lambda_i'-\lambda_j'}(\theta_{ij})
                    % \HellH{(ij)\to i,j}_{\lambda_i',\lambda_j'}
                    X_s^{\tau,\lambda_k';\lambda_i',\lambda_j'}(\sigma_k)\,
                    d^{s}_{\tau,\lambda_i'-\lambda_j'}(\theta_{ij})
                    \\ \nonumber
                    & \hspace{2cm} \times
                    d^{j_1}_{\lambda_1',\lambda_1}({\color{colc}\wigner^{1}_{k(0)}})\,
                    d^{j_2}_{\lambda_2',\lambda_2}({\color{colc}\wigner^{2}_{k(0)}})\,
                    d^{j_3}_{\lambda_3',\lambda_3}({\color{colc}\wigner^{3}_{k(0)}}),
      \end{align*}
      \vspace{1mm}
  \end{block}
  \begin{columns}
    \begin{column}{0.61\textwidth}
      \begin{itemize}
        \item Three decay chains, $(ij)k\in\{(12)3, (23)1, (31)2\}$.
        \item $\theta_{ij} = \theta_{ij}(\{\sigma\})$ is an isobar decay angle
        \item ${\color{colc}\hat{\theta}_{k(1)}} = {\color{colc}\hat{\theta}_{k(1)}}(\{\sigma\})$ is the particle-$0$ Wigner angle
        \item ${\color{colc}\wigner^{i}_{k(0)}} = {\color{colc}\wigner^{i}_{k(0)}}(\{\sigma\})$ is the particle-$i$ Wigner angle
        % \item $X_s^{\tau,\lambda_k';\lambda_i',\lambda_j'}(\sigma_k) \Rightarrow X_{s}^{LS;l's'}(\sigma_k)$ is the only model-dependent input (lineshape functions)
    \end{itemize}
      \end{column}
    \begin{column}{0.38\textwidth}
      \begin{exampleblock}{Applied in LHCb}
        \begin{itemize}
          \item $P_c$ in $\Lb\to J/\psi p K^-$
          \item $P_{cs}$ in $\Xi_b^-\to J/\psi \Lambda K^-$
          \item $\Lambda_c^+/\Xi_c^+ \to pK^-\pi^+$
          \item Some analyses in progress
        \end{itemize}      
      \end{exampleblock}
    \end{column}
  \end{columns}
\end{frame}

\begin{frame}{Symmetrization: $\underbrace{(K^-p)}_\text{high} K^- + K^-\underbrace{(p K^-)}_\text{low}$\hfill\paper{arXiv:2104.15074}}
  \begin{columns}
    \begin{column}{0.3\textwidth}
      \includegraphics[width=\textwidth]{conf1.pdf}
    \end{column}
    \begin{column}{0.65\textwidth}
      \begin{align*}
        A_{\lambda_0,\lambda} = \sum_{\nu} D_{\lambda_0,\nu}^{1/2}(\alpha,\beta,\gamma) O_{\lambda}^{\nu}(m_{\text{high}}^2, m_{\text{low}}^2)
      \end{align*}
      The helicity amplitude with explicit permutation symmetry:
      $$
      O^\nu_{\lambda}    = T^\nu_{\lambda}(m_{\text{high}}^2, m_{\text{low}}^2) \quad\fbox{\color{red}$+$}\quad
        {\color{cola} (-1)^{\nu+\lambda}} T^\nu_{\lambda}(m_{\text{low}}^2, m_{\text{high}}^2)
      $$
      $T^\nu_{\lambda}$ is the resonance decay amplitude $\Xi_b^-\to R^0(\to K^- p)K^-$.
    \end{column}
  \end{columns}
  \begin{exampleblock}{}{}
    {\color{cola} $(-1)^{\nu+\lambda}$}: permutation of kaons $K_1^- \leftrightarrow K_3^-$ flips the $x$-$z$ plane $\Rightarrow R_z(\pi)$
  \end{exampleblock}
  \begin{block}{}
    \centering
    Clearly $\fbox{\color{red}$+$}$ in covariant: 
    $A = \bar{u}(p,\lambda) \left[\frac{\slashed{p}_{R_1}+m_{\text{high}}}{2m_{\text{high}}^2} {\color{red}+} \frac{\slashed{p}_{R_3}+m_{\text{low}}}{2m_{\text{low}}^2} \right] u(p_b,\nu)$
    $\Rightarrow$ check!
  \end{block}
\end{frame}

