  \begin{block}{Symmetries of the decay}
    \begin{itemize}
      \item Resonances in $J/\psi p$ and $J/\psi \bar{p}$ are CP-conjugated
      \item Initial state ($B_s$) is not flavor-tagged $\Rightarrow$ symmetric model 
      \item Non-resonant $p\bar{p}$ with $J^P_{X} = 1^{--}$ is null-hypothesis (CP-even).
      \item Combination of $P_c^+$ and $P_c^-$ is CP-odd $\Rightarrow$ total interference vanishes 
      \item For $J^P_{P_c} = 1/2^+,  3/2^-$,
        interference of $P_c^+ + P_c^-$ with $X$ vanishes on Dalitz\\
        (PC vs PV decays)
    \end{itemize}
  \end{block}
