\begin{frame}{Summary on $a_1(1420)$}{}
  \begin{alertblock}{} % The story of $a_1(1420)$
    \begin{itemize}
        \item Peak and phase motion are not unique sign of a resonance!
        \item $a_1(1420)$ signal can be described with ordinary $a_1$ as source
        for the rescattering via the triangle diagram
        \item Old theoretical concept, but clearly observed for the first time!
        \item Intensity of signal $\sim 1\%$, in agreement with experiment
    \end{itemize}
