\section{Summary}

\begin{frame}{Conclusions and outlook}{} % Hadron spectroscopy is fascinating
  \begin{block}{}
    \begin{itemize}
      \item Hadron \textbf{spectroscopy} is a unique tool for understanding the QCD, the theory of matter formation
      \item \textbf{Diffractive} reaction is a clean setup for measurements of the excitation spectrum
      \item \textbf{COMPASS} leads the effort of large combined light-quark meson studies
      \item Many new surprises with new data (GlueX, BESIII, AMBER(?))
      \item Lattice QCD already provides quantities accessible at COMPASS,\\
      we should catch up
      \item Strengthen the TH+EXP collaboration
    \end{itemize}
  \end{block}
  \pause
  \begin{alertblock}{Outlook for hadron spectroscopy at COMPASS}
    \begin{itemize}
      \item $\pi_1(1600) \to b_1\pi$ and $\pi_1(1600) \to f_1\pi$ are under study in COMPASS
      \item Kaon diffraction reaction $K^-\,p\to K^-\pi^+\pi^-\,p$ is under study\\
      The first results are coming soon
      \item Extensive kaon spectroscopy program with AMBER at CERN is proposed
    \end{itemize}
  \end{alertblock}
\end{frame}

