\begin{frame}{Julia in my projects}{Interface between theory and experiment needs non-standard functions, flexibility}
  \begin{center}
    $\sim$ 2017:\quad\quad Mathematica / C$++$ $\Rightarrow$ Julia
  \end{center}
  \begin{itemize}
    \item \paper{\textbf{JPAC}, PRD 98 (2018)}: Studies of the $a_1(1260)$
    \begin{itemize}
      \item Coding complex parametrization
      \item Binned fit with \texttt{NLopt}.
      \item Analytic continuation
    \end{itemize}
    \item \paper{\textbf{COMPASS}, PRL 127 (2021) 8, 082501}: Triangle Singularity as the Origin of the $a_1(1420)$
    \begin{itemize}
      \item Coding complex parametrization (cross check for C++)
      \item Final plotting
    \end{itemize}
    \item \paper{\textbf{LHCb}, PRD Lett., 2107.03419}: $\Omega_c^{**0}$ in $\Omega_b^+$ decays
    \begin{itemize}
      \item Event processing: cut-bases selection
      \item Event-based log-likelihood fitting
    \end{itemize}
    \item \paper{\textbf{LHCb}, submitted to Nature Physics}: Study of the doubly charmed tetraquark $T_{cc}^+$
    \begin{itemize}
      \item Coding complex parametrization (cross check for C++)
      \item Analytic studies: integrals, complex algebra
    \end{itemize}
  \end{itemize}
\end{frame}

\begin{frame}{Workflow in LHCb analysis}
Workflow:
\begin{enumerate}
  \item Course selection on event topology: {\color{gray} \texttt{python/DSL} to configure C$++$ algorithms of \href{https://gitlab.cern.ch/lhcb/Gaudi}{\texttt{Gaudi}}}
  \item Pre-Selection (done via distributed computation grid): {\color{gray} \texttt{python/DSL} to configure C$++$}
  \item Fine event selection -- NN/BDT: {\color{gray} \texttt{python/C++}}
  \item Extraction of physics: {\color{gray} \texttt{python/C++}}
\end{enumerate}
\begin{alertblock}{}
  The steps 3 and 4 can be done by Julia.
\end{alertblock}
The reason why it is not done:
\begin{itemize}
  \item Code inheritance: many standard steps (BDTs) across many analysis
  \item Number of non-C++ precedents is very low
\end{itemize}
