\begin{frame}{Minimizers}{Replace \texttt{Minuit}}
  Optimizers in Julia:
  \begin{itemize}
    \item \texttt{Optim.jl}: implement \texttt{BFGS}
    \begin{itemize}
      \item Suggests a common interface of minimization: \texttt{NLSolversBase}
    \end{itemize}
    \item \texttt{NLopt.jl}: calls \texttt{BFGS}
    \begin{itemize}
      \item C++ wrapper, works
    \end{itemize}
    \item \texttt{iminuit} via \texttt{PyCall.jl}: calls \texttt{MIGRAD}, pre-version of \texttt{BFGS}
    \begin{itemize}
      \item Incredibly stable linear search, works where other (above) fail
      \item \texttt{iminuit} $1.54 \to 2.7.0$: versioning via \texttt{Conda.jl} is not straightforward
    \end{itemize}
  \end{itemize}
\end{frame}

\begin{frame}{Plotting in Julia}{Replace \texttt{ROOT}}
\begin{columns}
  \begin{column}{0.5\textwidth}
    \begin{itemize}
      \item \texttt{GR} via \texttt{Plots.jl}
      \begin{itemize}
        \item Super fast, publication quality
        \item Convenient recipe system
        \item Relatively easy to implement hacks
        \item Might be unstable, misses hep-related recipes
      \end{itemize}
      \item \texttt{PGFplotsX.jl}: LaTeX plots
      \item \texttt{PlotlyJS.jl}: interactive
    \end{itemize}
    \end{column}
