\begin{frame}{Main concepts of Julia}
  Julia is a programming language combining high-level ease with low-level performance
  \begin{itemize}
    \item \textbf{Fast}: compiles to native code on fly (JIT, LLVM)
    \item \textbf{Dynamic}: dynamically typed unless the type is specified
    \item \textbf{Composable}: the central paradigm is \textbf{multiple dispatch}
    \item \textbf{General}: metaprogramming, debugging, profiling, build-in package manager
    \item \textbf{Reproducible}: tracks all dependencies including binaries
    \item \textbf{Open source}: MIT license also for most of ecosystem packages
  \end{itemize}
  % Designed in 2009 in MIT. Solves two-language problem (fast C++ \& flexible python)
\end{frame}

\begin{frame}{Julia is growing fast}
  % In LHCb, we have 
  \begin{itemize}
    \item Over 4k registered packages
    \item over $20M$ downloads
    \item $78\%$ annual growth
    \item Over $80M$ GitHub stars
    % \item Julia is the first language after C, C++, and fortran to break 1 petaflop barrier
    \item JuliaCon: $\sim$500 attendees (2019), $\sim$10000 (2020), and >20000 (2021)
  \end{itemize}
\end{frame}

