\begin{frame}[noframenumbering]{Rederivation of the Landau-Yang theorem\hfill\paper{arXiv:2007.05501}}
  \begin{center}
    \fbox{"A massive particle with spin 1 cannot decay into two photons", wikipedia}
  \end{center}
\begin{block}{}
  Photons do not carry the longitudinal polarizarion $\Rightarrow$ $H_{0,i}=H_{i,0} = 0$
\end{block}
  \begin{align*}
    & \qquad H^{(\I)}&
    & \qquad H^{(\II)}&
    & \qquad H^{(\III)}&
    & \qquad H^{(\IV)}&\\
    &\begin{pmatrix}
      b & a & c\\
      a & d\verline & a\\\overtabline
      c & a & b
    \end{pmatrix}_S&
    &\begin{pmatrix}
      b & a &  \\
      a & {\color{white}0}\verline & -a\\\overtabline
        & -a & -b
    \end{pmatrix}_S&
    &\begin{pmatrix}
        & a &  \\
      -a & {\color{white}0}\verline & -a\\\overtabline
        & a &
    \end{pmatrix}_A&
    &\begin{pmatrix}
        & a & c\\
      -a & {\color{white}0}\verline & a\\\overtabline
      -c & -a &
    \end{pmatrix}_A\\
    &\begin{pmatrix}
      b & {\color{white}a} & {\color{white}c}\\
      {\color{white}a} & d\verline & {\color{white}a}\\\overtabline
      {\color{white}c} & {\color{white}a} & b
    \end{pmatrix}_S&
    &\begin{pmatrix}
      b & {\color{white}a} &  \\
      {\color{white}a} & {\color{white}0}\verline & {\color{white}-a}\\\overtabline
        & {\color{white}-a} & -b
    \end{pmatrix}_S&
    &{\color{white} \begin{pmatrix}
        & {\color{white}a} &  \\
      {\color{white}-a} & \verline  & {\color{white}-a}\\
        & {\color{white}a} &
    \end{pmatrix}_A}&
    &\begin{pmatrix}
        & a & {\color{white}c}\\
      -a & {\color{white}0}\verline & a\\\overtabline
      {\color{white}-c} & -a &
    \end{pmatrix}_A\\
    & \qquad \fbox{$0^+$}&
    & \qquad \fbox{$0^-$}&
    & \qquad {\color{white} \fbox{$0^+$}}&
    & \qquad \fbox{$1^+$}&
  \end{align*}
  \vspace{-3mm}
  \begin{exampleblock}{}
    \centering
    No decay to two photons for $1^+$, and group-\III: $1^-$, $3^-$, $5^-$, \dots
  \end{exampleblock}
\end{frame}



