\section{Introduction}

\begin{frame}{Why we want to know/measure polarization of hadrons?}
\begin{itemize}
    \item Mechanism of quark hadronization~\paper{Brambilla:2010cs, Faccioli:2010kd, Butenschoen:2012px}
    \item Hadron spectroscopy, extending decay chains (+ next slide)
    \begin{itemize}
        \item[$\checkmark$] $\Lambda_b^0 \to J/\psi p K$ with {\color{cola}$J/\psi \to \mu^+\mu^-$}
        \item[$\checkmark$] $B\to J/\psi \bar{p} \Lambda$ with {\color{cola}$\Lambda \to p \pi$}
        \item[$?$] $B^+ \to \varLambda_c^+\Lambda_c^- K^+$ with {\color{cola}$\varLambda_c^+ \to p K^- \pi^+$}
        \item[$?$] $\Omega_b^- \to \Xi_c^+ \pi^- K^-$ with {\color{cola}$\Xi_c^+ \to p K^- \pi^+$}
    \end{itemize}
    \item BSM searches with $\Lambda_b^0 \to \varLambda_c^+ l^-\nu$~\paper{Konig:1993wz, Dutta:2015ueb, Shivashankara:2015cta, Li:2016pdv, Li:2016pdv, Datta:2017aue, Ray:2018hrx, DiSalvo:2018ngq, Penalva:2019rgt, Ferrillo:2019owd}
    \begin{itemize}
        \item E.g. sign of the longitudinal polarization of $\varLambda_c^+$ provides a test for
        the left-handedness of the $b\to c$ current.
    \end{itemize}
    \item BSM searches with measurement of EDM with the charm meson
\end{itemize}
\end{frame}

