\begin{frame}{Decay of fermion is special. Example $\Lambda\to p\pi^-$}{Baryon in the final state averages angular distriburions}
    \begin{center}
        \includegraphics[width=0.6\textwidth]{Ldecay.pdf}            
    \end{center}
    \vspace{-5mm}
    \begin{align*}
        H_{\lambda} = \left\langle p,\lambda; K^-| T_\text{weak} |\Lambda,\lambda \right\rangle: \text{ hadron property}
    \end{align*}
    $$
    \frac{2}{\Gamma}\frac{\diff \Gamma}{\diff\cos\theta} = 1 + P \alpha \cos\theta\,,\qquad A_{FB} = \alpha P:\text{  asymmerty}
    % \frac{\diff N}{\diff \cos\theta} = N(1+\alpha P\cos\theta),\qquad A_{FB} = \alpha P:\text{  asymmerty}
    $$
    \begin{itemize}
        \item $P = |\vec{P}|$ polarization, for $J=1/2$, there are just tree d.o.f.
        \item $\alpha$ is the asymmetry parameter (analysing power of the decay)
    \end{itemize}
    \begin{alertblock}{}\centering
        $\varLambda(j^P = 1/2^\colred{+}) \to p(j^P = 1/2^\colred{+}) \,\pi^-(j^P = 0^\colred{-})$:
        \begin{itemize}
            \item S-wave -- parity violating (PV); P-wave -- parity conserving (PC)
        \end{itemize}
        $
        \alpha = \frac{|H_{+}|^2-|H_{-}|^2}{|H_{+}|^2 + |H_{-}|^2} = -\frac{2\text{Re}(H_S^* H_P)}{|H_S|^2 + |H_P|^2} \quad \text{both PV and PC are needed!}
        $    
    \end{alertblock}
\end{frame}


\begin{frame}{Polarimetry in $\tau$ decays}
    {\paper{Tsai:1971vv, Kuhn:1991cc, Davier:1992nw, Kuhn:1995nn, Kuhn:1982di, Kuhn:1993ra, Hagiwara:1989fn}}
\begin{align*}
    \frac{\Phi}{\Gamma}\,\frac{\diff \Gamma}{\mathrm{d}\Phi} \propto 1+ \vec{P}\cdot\vec{h}\,.
\end{align*}
\begin{itemize}
    \item $\vec P$ is a polarization of $\tau$
    \item $\vec{h}$ is a polarimeter vector
\end{itemize}
\begin{block}{$\tau$ polarimeter in the SM}
    \begin{itemize}
        \item Unit vector, $|\vec{h}| = 1$
        \item direction depends on the final state
        \begin{itemize}
            \item For \mbox{$\tau^- \to \pi^- \nu_\tau$} decay,
            $\vec{h}$ points to the pion
            \item for $\tau^-\to l^- \nu_\tau \bar{\nu}_l$ decay, $\vec h \uparrow \uparrow p_{\bar{\nu}}$.
        \end{itemize}
    \end{itemize}
\end{block}
\end{frame}

\begin{frame}{Dalitz-plot decomposition}{Factorization of variables decribing the system}
{\Large
\begin{align*}
    &T_{\nu_0,\{\lambda\}}(\phi,\theta,\chi; \tau) = \\
        &\qquad\qquad\sum_{\nu} {\color{cola} D_{\nu_0,\nu}^{1/2}(\phi,\theta,\chi)}
         \, 
         {\color{colb} A_{\nu,\{\lambda\}}(\tau)} % m_{pK}, m_{\pi K}
\end{align*}}
\begin{columns}
    \begin{column}[]{0.5\textwidth}
        {\color{cola}\textbf{Polarization d.o.f.}}        
    \end{column}
    \begin{column}[]{0.5\textwidth}
        {\color{colb}\textbf{Dynamic d.o.f.}}
    \end{column}
\end{columns}
\begin{columns}
    \begin{column}[]{0.5\textwidth}
        \centering
        \begin{itemize}
            \item Euler angles in active ZYZ convention
            \item Rotation of the system as rigid body
            \item $pp \to \varLambda_c^+ X$: $({\color{cola}\theta,\phi})$ angles of $\varLambda_c^+$
            \item $\varLambda_c^+ \to K^* p$:  $(\theta_{K}, {\color{cola}\chi})$ angles of $K^*$
            \item Dependence of the angles reflects polarization
        \end{itemize}
    \end{column}
    \begin{column}[]{0.5\textwidth}
        \centering
        \begin{itemize}
            \item Resonances in the decay
            \item $m_{K\pi}$, $m_{\pi p}$, $m_{p K}$ masses of subsystems (dependent)
            \item angular distribution
        \end{itemize}
    \end{column}
\end{columns}
\end{frame}

\begin{frame}{Polarized decay rate}
\begin{align*}
    \left|\mathcal{M}\right|^2 = \sum_{\nu_0,\nu_0',\{\lambda\}}\mathfrak{R}_{\nu_0',\nu_0} T_{\nu_0',\{\lambda\}}^* T_{\nu_0,\{\lambda\}}\,,
\end{align*}
\begin{align*}
    \mathfrak{R}_{\nu_0',\nu_0} = \frac{1}{2}\left(1+\vec P \cdot \vec \sigma^P\right)_{\nu_0',\nu_0}\,,
\end{align*}\pause
\begin{block}{Note on algebra}
    SU(2) is double cover of SO(3): \hfill spin $1/2$, $4\pi$ rotation\\
    The explicit homomorphism with the non-trivial center:
    $$
    \phi: \text{SU(2)} \to \text{SO(3)},\qquad \phi(d) = R\,,
    $$
    $$
    \phi(d) = \frac{1}{2}\text{Tr}\left[
    D^{1/2*}(\phi,\theta,\chi) \sigma^P_i D^{1/2}(\phi,\theta,\chi) \sigma^P_j
    \right] = R_{ij}(\phi,\theta,\chi),
    $$
\end{block}
\end{frame}

\begin{frame}{Model-agnostic representation of the decay rate}{Our master formula}
After some gymnastic,
\begin{align*}
    \left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2 =
        \unpolrate(\tau)\,
        \bigg(1 + \sum_{i,j} P_i R_{ij}(\phi, \theta, \chi) \alpha_j(\tau) \bigg)\,,
\end{align*}
where
\begin{itemize}
    \item $\unpolrate(\tau)$ is the unpolarized intensity
    \item $\alpha(\tau)$ is the aligned polarimeter vector,
    $$
    \vec\alpha(\tau) =  \sum_{\nu',\nu,\{\lambda\}} A^{*}_{\nu',\{\lambda\}}\vec\sigma_{\nu',\nu}  A_{\nu,\{\lambda\}} \,\big /\, \unpolrate(\tau)\,.
    $$
    it is specific for the decay, does not depend on the production mechanism.
    \item $\alpha$ can be computed for any model, parametrized on the grid, splines, \dots
\end{itemize}
\end{frame}


\begin{frame}{Averaging over the dynamic variables}{The polarization measurement can be even simpler}
    Can the dynamic variables $\tau$ be integrated over, i.e disregarded in the analysis?
\begin{align*}
    \frac{8\pi}{\Gamma}\frac{\diff^3 \Gamma}{\diff\phi\,\diff\cos\theta\,\diff\chi} = 1+\sum_{i,j}P_i R_{ij}(\phi, \theta, \chi) \overline{\alpha}_j\,,
\end{align*}
where
\begin{itemize}
    \item $\vec{\overline{\alpha}}$ is averaged aligned polarimeter vector
    \item Just three known numbers needs to be known to determine polarization
    \item The uncertainty on $P$ with integrated setup is worse than with the full dimensions. 
\end{itemize}
\end{frame}


\begin{frame}{Polarization sensitivity by Davier et al.}
Determination of polarization is a linear problem
$$
\unpolrate(\xi|P) = f(\xi) + P g(\xi)\,,\quad
\text{where }\xi\text{ are kinematic variables.}
$$
For the likelihood fit of the set $\{\xi_i\}_N$,
the error to $P$ can be computed analytically:
$$
P = P_\text{mod} \pm \delta_P, \quad \delta_P = \frac{1}{S_P\sqrt{N}},
\text{ where }
S_P^2 = \int \frac{g^2}{f+P g} d^n \xi
$$
\begin{alertblock}{Using the relations with our master formula}
$$
S_0 = 3 \int \unpolrate \left|\vec{\alpha}\right|^2 \diff^n \tau \,\big /\, \int \unpolrate\,\diff^n \tau
$$
\begin{itemize}
    \item For integrated setup, 
    $\overline{S}_0^2 = 3(\overline{\alpha}_x^2+\overline{\alpha}_y^2+\overline{\alpha}_z^2)$
    \item The ratio $S_0 / \overline{S}_0$ gives the expected increase of the statistical uncertainty
\end{itemize}
\end{alertblock}
\end{frame}

\begin{frame}{Analysis strategy}
\begin{itemize}
    \item Amplitude analysis of $\Lambda_{c}^+\to pK^-\pi^+$ is finished, LHCb-PAPER-2022-002
    \item The model-agnostic representation will foster reusing the results in LHCb and beyond
\end{itemize}
\begin{exampleblock}{}
    \begin{itemize}
        \item Implement $\varLambda_c^+\to pK^-\pi^+$ model from LHCb-PAPER-2022-002
        \item Compute $\vec{\alpha}$ for every point of the $pK^-\pi^+$ Dalitz plot
        \item Propagate uncertainties of the angular analysis
    \end{itemize}
\end{exampleblock}    
\begin{alertblock}{Results:}
    \begin{itemize}
        \item Four distributions $I_0$, $\alpha_x$, $\alpha_y$, and $\alpha_z$, computed on a grid of $m_{pK} \times m_{\pi K}$;
        \item Stat./syst. uncertainties to the maps;
        \item Averaged values, $\overline{\alpha}_x$, $\overline{\alpha}_y$, and $\overline{\alpha}_z$;
        \item Loss of precision when using $\vec{\overline{\alpha}}$
        \item Example of application, CPV properties of $\vec \alpha$.
    \end{itemize}
\end{alertblock}
\end{frame}

