\begin{frame}{Polarimeter field in Dalitz coordinates}{}
	\centering%
	\begin{columns}%
		\begin{column}{0.35\textwidth}
            \centering
			Amplitude to polarimeter:
			\scalebox{0.9}{\parbox{\textwidth}{
            \begin{align*}
				\vec\alpha(\tau) =  \sum_{\nu',\nu,\{\lambda\}} A^{*}_{\nu',\{\lambda\}}\vec\sigma_{\nu',\nu}  A_{\nu,\{\lambda\}} \,\big /\, I_0(\tau)
			\end{align*}}}
			Polarimeter to intensity:
			\scalebox{0.9}{\parbox{\textwidth}{
                \begin{align*}
				 & \left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2 =
				I_0(\tau)\,                                                                               \\
				 & \quad \times\left(1 + \sum_{i,j} P_i R_{ij}(\phi, \theta, \chi) \alpha_j(\tau) \right) \\
				 & R(\phi, \theta, \chi) = R_Z(\phi) R_Y(\theta) R_Z(\chi)
			\end{align*}}}
		\end{column}%
		\begin{column}{0.6\textwidth}%
			\centering
			\footnotesize
			Aligned polarimeter vector field $\vec\alpha$
			\adjustbox{clip=true,trim=0 0 0 16}{%
				\includegraphics[width=.95\textwidth]{figures/total-polarimetry-field.pdf}%
			}%
		\end{column}%
	\end{columns}%
\end{frame}

