\begin{frame}{Propagation of the uncertainties}
	{}
	\begin{columns}
		\begin{column}{0.54\textwidth}
			Uncertainties over the polarimeter field have two components:
			\begin{itemize}
				\item \textbf{statistical}:
				      \begin{itemize}
					      \item parameter \textbf{resampling} of the nominal model using parameter error bars
					      \item RMS over the resulting parameter-resampled distributions
				      \end{itemize}
				\item \textbf{model:}
				      \begin{itemize}
					      \item implement alternative models
					      \item only central values of alternative models are considered
					      \item take min-max extrema
				      \end{itemize}
				\item \textbf{systematic:}                      
                    \begin{itemize}
                        \item Small compare to stat.\&model
                        \item included in the \textbf{resampling}.
                    \end{itemize}
            \end{itemize}
		\end{column}
		\begin{column}{0.43\textwidth}
			\includegraphics[width=\textwidth]{figures/fit-parameter-error-bars.png}%
		\end{column}
	\end{columns}
