\subsection{Polarimetry}
\begin{frame}{Measuring polarization -- two-body decays}{Decay of a fermion is special -- baryon in the final state averages angular distributions}
	\begin{minipage}{0.5\textwidth}
		{\large Example: $\Lambdares \to \proton \pim$}
		\begin{flalign*}
			H_{\lambda_{\Lambdares}, \lambda_{\proton}} = \left\langle \proton, \lambda_{\proton}; \pim| T_\mathrm{weak} |\Lambdares, \lambda_{\Lambdares} \right\rangle
			% : \text{ hadron property}
		\end{flalign*}
		\vspace*{-2em}
		\begin{flalign*}
			\frac{2}{\Gamma}\frac{\diff \Gamma}{\diff\cos\theta} = 1 + P \alpha \cos\theta\,,\quad A_{FB} = \alpha P
			% : \text{ asymmetry}
		\end{flalign*}
	\end{minipage}
	\begin{tikzpicture}[overlay, remember picture]
		\node[blend mode=multiply] at (3.2, 0.1) {\includesvg[width=0.5\textwidth]{Ldecay.svg}};
	\end{tikzpicture}
	\vspace*{0.7em}
	\begin{itemize}
		\item $P = |\vec{P}|$ polarization, for $J=1/2$, there are just tree d.o.f.
		\item $\alpha$ is the \textbf{asymmetry parameter} (analyzing power of the decay)
	\end{itemize}
	\begin{minipage}{0.75\textwidth}
		\begin{alertblock}{\centering Appears only when both PV and PC}
			\centering
			\vspace*{0.4em}
			{\large
			$\alpha = \frac{|H_{+}|^2-|H_{-}|^2}{|H_{+}|^2 + |H_{-}|^2} = -\frac{2\mathrm{Re}(H_{\color{cola}S}^* H_{\color{colb}P})}{|H_{\color{cola}S}|^2 + |H_{\color{colb}P}|^2}$ \\[0.7em]
			}
			${\color{cola}S}$-wave -- parity violating (PV); ${\color{colb}P}$-wave -- parity conserving (PC): \\[0.2em]
			$\Lambdares\,(j^P = 1/2^\colred{+}) \, \to \, \proton\,(j^P = 1/2^\colred{+}) \; \pim(j^P = 0^\colred{-})$
		\end{alertblock}
	\end{minipage}
	\only<2>{%
		\begin{tikzpicture}[overlay]
			\draw[line width=0.5pt, draw=BrickRed] (-9.9, 2.9) rectangle ++(3.9, 0.95);
			\draw[-stealth, draw=BrickRed] (0.9, 1.3) -- (-0.2, 2.8) -- (-5.9, 3.0);
			\node[align=left, draw=BrickRed, fill=white, text=BrickRed] at (0.75, 0.8) {%
				If we know $\alpha$, we can measure $P$. \\[0.5em]
				But what about \textbf{multibody} decays?%
			};
		\end{tikzpicture}
	}
\end{frame}


\begin{frame}{Measuring polarization -- polarimetry in $\Ptau$ decays}
	{\scriptsize\realcite{Tsai:1971vv, Kuhn:1991cc, Davier:1992nw, Kuhn:1995nn, Kuhn:1982di, Kuhn:1993ra, Hagiwara:1989fn}}
	Idea: similar relation for $\Ptau$ lepton decays,
	\begin{align*}
		\frac{\Phi}{\Gamma}\,\frac{\diff \Gamma}{\mathrm{d}\Phi} \propto 1+ \vec{P}\cdot\vec{h}\,.
	\end{align*}
	\begin{itemize}
		\item $\vec{P}$ is a polarization of $\Ptau$
		\item $\vec{h}$ is a \textbf{polarimeter vector}
	\end{itemize}
	\begin{block}{Polarimeter vector of the $\Ptau$ lepton in the SM}
		\begin{itemize}
			\item Direction depends on the final state, e.g.
			      \begin{itemize}
				      \item for \mbox{$\Ptau^- \to {\color{BrickRed}\pim} \neut$} decay, $\vec{h} \uparrow\uparrow \vec{p}_{\color{BrickRed}\pim}$
				      \item for $\Ptau^-\to \lepton \neut {\color{BrickRed}\neulb}$ decay, $\vec{h} \uparrow\uparrow \vec{p}_{\color{BrickRed}\neulb}$
			      \end{itemize}
			\item Unit vector: $|\vec{h}| = 1$.
		\end{itemize}
	\end{block}
\end{frame}

\begin{frame}{Measuring polarization -- general multibody decays?}{$\rightarrow$ Dalitz-Plot Decomposition (DPD)}
	Factorization of variables describing dynamics and polarization~\cite{JPAC:2019ufm}:
	{%
	\Large
	\begin{equation*}
		T_{\nu_0,\{\lambda\}}(\phi,\theta,\chi; \tau) = \sum_{\nu}
		{\color{cola} D_{\nu_0,\nu}^{1/2}(\phi,\theta,\chi)}
		\,
		{\color{colb} A_{\nu,\{\lambda\}}(\tau)}
	\end{equation*}%
	}
	\vspace*{-1em}
	\begin{columns}[T]
		\begin{column}{0.5\textwidth}
			{\centering\color{cola}\textbf{Polarization d.o.f.}}
			\begin{itemize}
				\item Euler angles in active ZYZ convention
				\item rotation of the system as rigid body
				\item polarization affects angular distribution
			\end{itemize}
			~\\
			{\centering\color{colb}\textbf{Dynamic d.o.f.}}
			\begin{itemize}
				\item Mandelstam variables of the subsystems
				\item describes resonances in the decay
			\end{itemize}
		\end{column}
		\begin{column}{0.5\textwidth}
		\end{column}
	\end{columns}
	\begin{tikzpicture}[overlay, remember picture]
		\node[blend mode=multiply] at (9.8, 1.6) {%
			\includesvg[width=0.6\textwidth]{angle-definitions-red.svg}%
		};
	\end{tikzpicture}
\end{frame}

\begin{frame}[t]{Model-agnostic representation of the decay rate}
	\hyperlink{subsec:homomorphism}{Using the SU(2) $\to$ SO(3) homomorphism}, we get our polarized \textbf{master formula}, \\[-1.5em]
	{\large
	\only<1>{%
		\begin{align*}
			\left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2 =
			\unpolrate(\tau)\,
			\left(1 + \sum_{i,j=1}^3 P_i R_{ij}(\phi, \theta, \chi) \alpha_j(\tau) \right)\,,
		\end{align*}
	}\only<2>{%
		\begin{align*}
			\color{gray}
			{\color{Green}{\left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2}} =
			{\color{Blue}{\unpolrate(\tau)}}\,
			\left(1 + \sum_{i,j=1}^3 {\color{red}{P_i}} {\color{Green}{R_{ij}(\phi, \theta, \chi)}} {\color{Blue}{\alpha_j(\tau)}} \right)\,,
		\end{align*}
	}} \\[-1em]
	where
	\only<2>{%
		\begin{tikzpicture}[overlay]
			\node[align=left] at (10.2, -1.0) {%
				\begin{minipage}{0.32\textwidth}
					\begin{block}{Determining polarization}
						\setlength{\leftmargini}{1.4em}
						\begin{enumerate}
							\item provide {\color{Blue}$I_0(\tau)$} and {\color{Blue}$\vec\alpha(\tau)$} \\
							\item measure {\color{Green}$\left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2$} \\
							\item get {\color{Red}$\vec{P}$} from fit
						\end{enumerate}
					\end{block}
				\end{minipage}
			};
			\draw[-, draw=Blue] (4.65, 0.65) -- (5.4, 0.0);  % I_0
			\draw[-, draw=Blue] (7.2, -0.15) -- (9.25, 0.75); % alpha
			\draw[-, draw=Blue] (7.2, -0.4) -- (8.0, -0.7); % [1]
			\node[align=left, text=Blue] at (6.3, -0.3) {\bfseries This study};
		\end{tikzpicture}
	}%
	\begin{itemize}
		\item $\unpolrate(\tau)$ is the unpolarized intensity
		\item $R(\phi, \theta, \chi) = R_Z(\phi) R_Y(\theta) R_Z(\chi)$ defines the \\
		      decay plane orientation.
		\item $\alpha(\tau)$ is the \textbf{aligned polarimeter vector} field, \\
		      {\large
		      $$
			      \vec\alpha(\tau) =  \sum_{\nu',\nu,\{\lambda\}} A^{*}_{\nu',\{\lambda\}}\vec\sigma_{\nu',\nu}  A_{\nu,\{\lambda\}} \,\big /\, \unpolrate(\tau)\,.
		      $$
		      }
		      It is specific for the decay, \textsl{does not depend on the production mechanism}.
	\end{itemize}
\end{frame}


\begin{frame}{Another application: extending amplitude models}
	{Example: $B^+ \to \Lc \Lcbar \Kp, \quad {\color{BrickRed}\Lz_{\cquark} \to \proton \kaon \pion}$}
	\begin{minipage}{0.7\textwidth}
		Normally, without polarization taken into account:
		\begin{align*}
			 & I\left(m_{\Lc K^+}^2, m_{\Lcbar K^+}^2\right) = \sum_{\nu_0,\bar{\nu}_0}
			\left| O_{\nu_0,\bar{\nu}_0}^{B}(m_{\Lc K^+}^2, m_{\Lcbar K^+}^2) \right|^2
		\end{align*}
		\begin{tikzpicture}[overlay]
			\node at (11.4, 1.4) {%
				\begin{minipage}{.46\textwidth}
					\begin{block}{Physics motivation}
						\setlength{\leftmargini}{1.2em}
						\begin{itemize}
							\item exotic structures in $\Lc \Lcbar$
							\item studies of $\Xic^{**}$ in $\Lc \kaon$
						\end{itemize}
						{\footnotesize\realcite{BaBar:2007xtc, Belle:2017jrt, Belle:2018yob, LHCb:2022vns}}
					\end{block}
				\end{minipage}
			};
		\end{tikzpicture}
		\pause
		Polarimeter provides \textbf{10 additional degrees of freedom}:
		\begin{align*}
			 & I\left(m_{\Lc \Kp}^2, m_{\Lcbar \Kp}^2;
			{\color{colc} \phi},
			{\color{colc} \theta},
			{\color{colc} \chi},
			{\color{colc} m_{\proton\Km}^2},
			{\color{colc} m_{\Km\pip}^2};
			{\color{colc} \bar{\phi}},
			{\color{colc} \bar{\theta}},
			{\color{colc} \bar{\chi}},
			{\color{colc} m_{\antiproton\Kp}^2},
			{\color{colc} m_{\Kp\pim}^2}
			\right) =                                                                                                                                                            \\
			 & \quad\sum_{\nu_0,\bar{\nu}_0,\nu,\bar{\nu}}
			\sum_{\nu_0',\bar{\nu}_0',\nu',\bar{\nu}'}
			O_{\nu_0',\bar{\nu}_0'}^{B*}(m_{\Lc \Kp}^2, m_{\Lcbar \Kp}^2)
			O_{\nu_0,\bar{\nu}_0}^B(m_{\Lc \Kp}^2, m_{\Lcbar \Kp}^2)                                                                                                             \\
			 & \qquad \times D^{1/2*}_{\nu_0',\nu'}(\phi,\theta,\chi) D^{1/2}_{\nu_0,\nu}(\phi,\theta,\chi) {\color{BrickRed} X_{\nu',\nu}^\Lc (m_{\proton\Km}^2,m_{\Km\pip}^2)} \\
			 & \qquad \times D^{1/2*}_{\bar{\nu}_0',\bar{\nu}'}(\bar{\phi},\bar{\theta},\bar{\chi}) D^{1/2}_{\bar{\nu}_0,\bar{\nu}}(\bar{\phi},\bar{\theta},\bar{\chi})\,
			{\color{BrickRed} X_{\bar{\nu}',\bar{\nu}}^\Lcbar(m_{\antiproton\Kp}^2,m_{\Kp\pim}^2)}
		\end{align*}
	\end{minipage}
	\begin{tikzpicture}[overlay]
		\node[align=left, draw=BrickRed, fill=white, text=BrickRed] at (0.7, -2.2) {%
			\large $X_{\nu',\nu}(\tau) \; =$  \\
			\large $\quad \frac{I_0(\tau)}{2} \left(1+\vec\alpha(\tau) \cdot \vec\sigma^{P}\right)_{\nu',\nu}$
		};
		\node[text=BrickRed] at (0.5, -3.15) {\bfseries No need to fit these d.o.f.};
	\end{tikzpicture}
\end{frame}


\begin{frame}{Optional simplification: averaging over dynamic variables}
	Can the dynamic variables $\tau$ be integrated over, i.e disregarded in the analysis?
	{\large
	\begin{align*}
		\frac{8\pi}{\Gamma}\frac{\diff^3 \Gamma}{\diff\phi\,\diff\cos\theta\,\diff\chi} = 1+\sum_{i,j=1}^3 P_i R_{ij}(\phi, \theta, \chi) \overline{\alpha}_j\,,
	\end{align*}
	}
	where $\vec{\overline{\alpha}}$ is \textbf{averaged aligned polarimeter vector}.\\[1em]
	\begin{alertblock}{Advantage / Disadvantage}
		\setlength{\leftmargini}{1.5em}
		\begin{itemize}
			\item[\color{Green}$+$] Only need know three numbers in order to determine polarization.
			\item[\color{Red}$-$] Uncertainty on $\vec{P}$ with averaged $\vec{\overline{\alpha}}$ is worse than with the full $\vec\alpha(\tau)$ field. \cite{Davier:1992nw}
		\end{itemize}
	\end{alertblock}
\end{frame}


\begin{frame}<presentation:0>{Polarization sensitivity by Davier et al.}
	Determination of polarization is a linear problem
	$$
		\unpolrate(\xi|P) = f(\xi) + P g(\xi)\,,\quad
		\text{where }\xi\text{ are kinematic variables.}
	$$
	For the likelihood fit of the set $\{\xi_i\}_N$,
	the error to $P$ can be computed analytically:
	$$
		P = P_\text{mod} \pm \delta_P, \quad \delta_P = \frac{1}{S_P\sqrt{N}},
		\text{ where }
		S_P^2 = \int \frac{g^2}{f+P g} d^n \xi
	$$
	\begin{alertblock}{Using the relations with our master formula}
		$$
			S_0 = 3 \int \unpolrate \left|\vec{\alpha}\right|^2 \diff^n \tau \,\big /\, \int \unpolrate\,\diff^n \tau
		$$
		\begin{itemize}
			\item For integrated setup,
			      $\overline{S}_0^2 = 3(\overline{\alpha}_x^2+\overline{\alpha}_y^2+\overline{\alpha}_z^2)$
			\item The ratio $S_0 / \overline{S}_0$ gives the expected increase of the statistical uncertainty
		\end{itemize}
	\end{alertblock}
\end{frame}


