\begin{frame}{Effective range and Weinberg compositeness}{}
  Non-relativistic expansion near the threshold:
  $$
  \mathcal{A}^{-1}_\text{NR} = \frac{1}{a} + r\frac{k^2}{2} + O(k^4) - ik
  $$
  \vspace{-5mm}
  \begin{columns}
    \begin{column}[]{0.48\textwidth}
      \begin{block}{\centering Scattering length, $a$}
        \begin{itemize}
          \item a characteristic size of the state
          \item $a > 0$: moderate interaction
          \item $a < 0$: strong attraction forming a bound state
        \end{itemize}
        % p n: a=-5.42 fm, r=1.75 fm
        % n n: a=23.71 fm, r=2.73 fm
      \end{block}
    \end{column}
    \begin{column}{0.48\textwidth}
      \begin{block}{\centering Effective range, $r$}
        \begin{itemize}
          \item is the second order correction
          \item[!] always positive in potential scattering\\
          \paper{Landau-Smorodinsky(1944), Esposito(2021)}
        \end{itemize}
      \end{block}
    \end{column}
  \end{columns}
  $$
  \text{Weinberg compositeness: } X \equiv 1-Z = \sqrt{\frac{1}{1+2r/a}}
  $$
  \begin{center}
    $X = 1:$ composite (molecule)\quad\quad $X = 0$ elementary
  \end{center}
  \begin{alertblock}{}
    According to the Weinberg's compositeness,
    \begin{itemize}
      \item Any state coupled to continuum (i.e. can decay) has a molecule component
      \item Non-zero effective range is an indication of the compact component
    \end{itemize}
  \end{alertblock}
  \begin{textblock*}{0.4\textwidth}(0.73\textwidth,0.05\textheight)
    \paper{I. Matuschek et al., EPJA 57 (2021) 3}\\
    \paper{T. Sekihara et al., PTEP (2015) 063D04}\\
    \paper{Y.Li et al, PRD 105 (2022)}\\
    \paper{J.Song et al., EPJA 58 (2022) 7}\\
    \end{textblock*}
\end{frame}




