\subsection{Uncertainties}

\begin{frame}[noframenumbering]{Propagation of uncertainties}
  \setlength{\leftmargini}{1.5em}
  \setlength{\leftmarginii}{1em}
  \begin{columns}[T]
    \begin{column}{0.48\textwidth}
      Uncertainties over the polarimeter field have two components: \\[0.5em]
      \begin{enumerate}
        \item {\color{cola}\textbf{Statistical} + \textbf{Systematic}}:
              \begin{itemize}
                \item parameter resampling of the default model using parameter error bars
                \item parameter error bars include both \\
                      stat. and syst. uncertainties, \\
                      added in quadrature
                \item take \textbf{RMS} over the resulting parameter-resampled distributions
              \end{itemize}
        \item {\color{colb}\textbf{Model}}:
              \begin{itemize}
                \item determined from all alternative models
                \item only central values of alternative models are considered
                \item take \textbf{min-max} of the extrema
              \end{itemize}
      \end{enumerate}
    \end{column}
    \begin{column}{0.51\textwidth}
      \vspace*{-.5em}
      \hfill{\tiny\realcite[p.~19]{LHCb-PAPER-2022-002}}\\[.5em]
