        \theta\left(\overline{\alpha}\right) & = & \left(+0.929 \pm 0.002_{-0.011}^{+0.017} \right) \times \pi\,,  & \text{\color{red} (small error!)} \\[1mm]
        \phi\left(\overline{\alpha}\right)   & = & \left(+0.955 \pm 0.045_{-0.028}^{+0.067} \right) \times \pi\,.  &
      \end{array}
    \end{align*}
  \end{exampleblock}
\end{frame}

