\begin{frame}[noframenumbering]{Model-agnostic representation of the decay rate}
  \hyperlink{subsec:homomorphism}{Using the SU(2) $\to$ SO(3) homomorphism}, we get our polarized \textbf{master formula}, \\[-1.5em]
  {\large
  \only<1>{%
    \begin{align*}
      \left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2 =
      \unpolrate(\tau)\,
      \left(1 + \sum_{i,j=1}^3 P_i R_{ij}(\phi, \theta, \chi) \alpha_j(\tau) \right)\,,
    \end{align*}
  }\only<2>{%
    \begin{align*}
      \color{gray}
      {\color{Green}{\left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2}} =
      {\color{Blue}{\unpolrate(\tau)}}\,
      \left(1 + \sum_{i,j=1}^3 {\color{red}{P_i}} {\color{Green}{R_{ij}(\phi, \theta, \chi)}} {\color{Blue}{\alpha_j(\tau)}} \right)\,,
    \end{align*}
  }} \\[-1em]
  where
  \only<2>{%
    \begin{tikzpicture}[overlay]
      \node[align=left] at (10.2, -1.0) {%
        \begin{minipage}{0.32\textwidth}
          \begin{block}{Determining polarization}
            \setlength{\leftmargini}{1.4em}
            \begin{enumerate}
              \item provide {\color{Blue}$I_0(\tau)$} and {\color{Blue}$\vec\alpha(\tau)$} \\
              \item measure {\color{Green}$\left|\mathcal{M}(\phi, \theta, \chi, \tau)\right|^2$} \\
              \item get {\color{Red}$\vec{P}$} from fit
            \end{enumerate}
          \end{block}
        \end{minipage}
      };
      \draw[-, draw=Blue] (4.65, 0.65) -- (5.4, 0.0);  % I_0
      \draw[-, draw=Blue] (7.2, -0.15) -- (9.25, 0.75); % alpha
      \draw[-, draw=Blue] (7.2, -0.4) -- (8.0, -0.7); % [1]
      \node[align=left, text=Blue] at (6.3, -0.3) {\bfseries This study};
    \end{tikzpicture}
  }%
  \begin{itemize}
    \item $\unpolrate(\tau)$ is the unpolarized intensity
    \item $R(\phi, \theta, \chi) = R_Z(\phi) R_Y(\theta) R_Z(\chi)$ defines the \\
          decay plane orientation.
    \item $\alpha(\tau)$ is the \textbf{aligned polarimeter vector} field, \\
          {\large
          $$
            \vec\alpha(\tau) =  \sum_{\nu',\nu,\{\lambda\}} A^{*}_{\nu',\{\lambda\}}\vec\sigma_{\nu',\nu}  A_{\nu,\{\lambda\}} \,\big /\, \unpolrate(\tau)\,.
          $$
          }
          It is specific for the decay, \textsl{does not depend on the production mechanism}.
  \end{itemize}
